'use client'

import { AlertCircle, ShieldCheck, TrendingDown, RefreshCcw, Info, CheckCircle2, XCircle } from 'lucide-react'
import { useState } from 'react'

interface AuditCardProps {
    finding: any
}

export function AuditCard({ finding: initialFinding }: AuditCardProps) {
    const [finding, setFinding] = useState(initialFinding)
    const [loading, setLoading] = useState(false)

    const typeLabels: any = {
        'duplicado': { label: 'Pago Duplicado', color: 'text-red-400', bg: 'bg-red-500/10', icon: RefreshCcw },
        'fuga_fiscal': { label: 'Fuga Fiscal', color: 'text-amber-400', bg: 'bg-amber-500/10', icon: TrendingDown },
        'anomalia': { label: 'Anomalía Atípica', color: 'text-blue-400', bg: 'bg-blue-500/10', icon: Info }
    }

    const style = typeLabels[finding.tipo] || typeLabels.anomalia
    const Icon = style.icon

    async function updateStatus(newStatus: string) {
        setLoading(true)
        try {
            const res = await fetch(`/api/findings/${finding.id}`, {
                method: 'PATCH',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ estado: newStatus })
            })

            if (res.ok) {
                setFinding({ ...finding, estado: newStatus })
            }
        } catch (error) {
            console.error('Error updating finding status:', error)
        } finally {
            setLoading(false)
        }
    }

    function formatCurrency(amount: number) {
        return new Intl.NumberFormat('es-AR', {
            style: 'currency',
            currency: 'ARS',
        }).format(amount)
    }

    if (finding.estado === 'ignorado' || finding.estado === 'resuelto') {
        return (
            <div className="bg-gray-900/50 border border-gray-800 rounded-2xl p-4 flex items-center justify-between opacity-60">
                <div className="flex items-center gap-3">
                    {finding.estado === 'resuelto' ? <CheckCircle2 className="text-emerald-500" /> : <XCircle className="text-gray-500" />}
                    <div>
                        <p className="text-sm font-bold text-white uppercase tracking-tighter">Hallazgo {finding.estado === 'resuelto' ? 'Resuelto' : 'Ignorado'}</p>
                        <p className="text-xs text-gray-500">{finding.detalle.razon}</p>
                    </div>
                </div>
                <button
                    onClick={() => updateStatus('detectado')}
                    className="text-xs text-emerald-500 hover:underline font-bold"
                >
                    Deshacer
                </button>
            </div>
        )
    }

    return (
        <div className="bg-gray-900 border border-gray-800 rounded-2xl p-6 hover:border-gray-700 transition-all group">
            <div className="flex flex-col md:flex-row gap-6 items-start">
                <div className={`p-4 rounded-xl ${style.bg} ${style.color}`}>
                    <Icon className="h-6 w-6" />
                </div>

                <div className="flex-1 space-y-2">
                    <div className="flex items-center gap-3">
                        <span className={`text-xs font-bold uppercase tracking-wider px-2 py-0.5 rounded ${style.bg} ${style.color}`}>
                            {style.label}
                        </span>
                        <span className="text-gray-500 text-xs">
                            Detectado el {new Date(finding.created_at).toLocaleDateString('es-AR')}
                        </span>
                    </div>

                    <h3 className="text-lg font-bold text-white">
                        {finding.detalle.razon || 'Anomalía detectada'}
                    </h3>

                    <div className="grid grid-cols-2 md:grid-cols-4 gap-4 mt-4 text-sm">
                        <div className="bg-black/20 p-3 rounded-lg border border-gray-800">
                            <p className="text-gray-500 text-xs mb-1">Monto Implicado</p>
                            <p className="font-mono text-white">
                                {formatCurrency(finding.transaccion.monto)}
                            </p>
                        </div>
                        <div className="bg-black/20 p-3 rounded-lg border border-gray-800">
                            <p className="text-gray-500 text-xs mb-1">Destinatario / CUIT</p>
                            <p className="text-white truncate">
                                {finding.transaccion.cuit || 'No disponible'}
                            </p>
                        </div>
                        <div className="bg-black/20 p-3 rounded-lg border border-gray-800">
                            <p className="text-gray-500 text-xs mb-1">Severidad</p>
                            <p className={`font-bold capitalize ${finding.severidad === 'critical' || finding.severidad === 'high' ? 'text-red-400' : 'text-amber-400'
                                }`}>
                                {finding.severidad}
                            </p>
                        </div>
                        <div className="bg-black/20 p-3 rounded-lg border border-gray-800">
                            <p className="text-gray-500 text-xs mb-1">Estado</p>
                            <p className="text-emerald-400 font-medium capitalize">
                                {finding.estado}
                            </p>
                        </div>
                    </div>

                    {finding.detalle.duplicate_of && (
                        <div className="mt-4 p-4 bg-emerald-500/5 rounded-xl border border-emerald-500/20">
                            <p className="text-[10px] font-bold text-emerald-400 uppercase tracking-widest mb-2">Transacción Original Detectada</p>
                            <div className="flex justify-between items-center text-sm">
                                <div className="space-y-1">
                                    <p className="text-white font-medium">{finding.detalle.duplicate_of.descripcion}</p>
                                    <p className="text-gray-500 text-xs">{new Date(finding.detalle.duplicate_of.fecha).toLocaleDateString('es-AR')}</p>
                                </div>
                                <div className="text-right">
                                    <p className="text-white font-mono">{formatCurrency(finding.detalle.duplicate_of.monto)}</p>
                                    <p className="text-[10px] text-gray-400">ID: {finding.detalle.duplicate_of.id?.substring(0, 8) || 'N/D'}</p>
                                </div>
                            </div>
                        </div>
                    )}

                    <div className="mt-4 p-4 bg-gray-800/30 rounded-xl border border-gray-800/50 flex flex-col md:flex-row justify-between items-center gap-4">
                        <p className="text-sm text-gray-300 italic flex-1">
                            "Hallazgo: {finding.detalle.razon}. {finding.detalle.duplicate_of ? `Este movimiento es idéntico a uno detectado el ${new Date(finding.detalle.duplicate_of.fecha).toLocaleDateString('es-AR')}.` : ''} {finding.detalle.historical_avg ? `El gasto histórico promedio es ${formatCurrency(finding.detalle.historical_avg)}.` : ''}"
                        </p>
                        {finding.transaccion.archivo_importacion_id && (
                            <button
                                onClick={() => {
                                    // Navigate to upload and open remap
                                    // For now, just trigger the event assuming the user is in Dashboard
                                    window.dispatchEvent(new CustomEvent('open-remap', {
                                        detail: {
                                            id: finding.transaccion.archivo_importacion_id,
                                            nombre_archivo: finding.transaccion.nombre_archivo || 'Archivo de Origen'
                                        }
                                    }))
                                    // Small UX hint: the user might need to go to Uploads tab
                                    alert('Se abrió el Asistente en la pestaña "Cargar Archivos"');
                                }}
                                className="text-[10px] bg-emerald-500/10 hover:bg-emerald-500/20 text-emerald-400 border border-emerald-500/30 px-3 py-1.5 rounded-lg flex items-center gap-2 font-bold transition-all"
                            >
                                <RefreshCcw className="w-3 h-3" />
                                CORREGIR MAPEO DE ORIGEN
                            </button>
                        )}
                    </div>
                </div>

                <div className="flex flex-col gap-2 w-full md:w-auto">
                    <button
                        onClick={() => updateStatus('resuelto')}
                        disabled={loading}
                        className="px-4 py-2 bg-emerald-600 hover:bg-emerald-500 text-white text-sm font-bold rounded-lg transition-colors disabled:opacity-50"
                    >
                        Resolver
                    </button>
                    <button
                        onClick={() => updateStatus('ignorado')}
                        disabled={loading}
                        className="px-4 py-2 bg-gray-800 hover:bg-gray-700 text-gray-300 text-sm font-medium rounded-lg border border-gray-700 transition-colors disabled:opacity-50"
                    >
                        Ignorar
                    </button>
                </div>
            </div>
        </div>
    )
}

'use client'

import { useState, useEffect } from 'react'
import {
    Dialog,
    DialogContent,
    DialogHeader,
    DialogTitle,
} from "@/components/ui/dialog"
import { createClient } from '@/lib/supabase/client'
import { Badge } from '@/components/ui/badge'
import { ScrollArea } from '@/components/ui/scroll-area'
import { Clock, Calendar, User, ArrowRight, CheckCircle2, AlertCircle, Landmark } from 'lucide-react'

interface HistoryEntry {
    id: string
    estado_anterior: string
    estado_nuevo: string
    created_at: string
    usuario_id: string
    motivo: string
    metadata: any
}

interface CheckHistoryModalProps {
    isOpen: boolean
    onClose: () => void
    checkId: string | null
    checkNumero: string | null
}

export function CheckHistoryModal({ isOpen, onClose, checkId, checkNumero }: CheckHistoryModalProps) {
    const [history, setHistory] = useState<HistoryEntry[]>([])
    const [loading, setLoading] = useState(false)
    const supabase = createClient()

    useEffect(() => {
        if (isOpen && checkId) {
            fetchHistory()
        }
    }, [isOpen, checkId])

    const fetchHistory = async () => {
        setLoading(true)
        try {
            const { data, error } = await supabase
                .from('instrumentos_pago_historial')
                .select('*')
                .eq('instrumento_id', checkId)
                .order('created_at', { ascending: false })

            if (error) throw error
            setHistory(data || [])
        } catch (error) {
            console.error('Error fetching check history:', error)
        } finally {
            setLoading(false)
        }
    }

    const getStatusIcon = (status: string) => {
        switch (status) {
            case 'pendiente': return <Clock className="w-4 h-4 text-gray-400" />
            case 'depositado': return <Landmark className="w-4 h-4 text-blue-400" />
            case 'acreditado': return <CheckCircle2 className="w-4 h-4 text-emerald-400" />
            case 'rechazado': return <AlertCircle className="w-4 h-4 text-red-400" />
            default: return <Clock className="w-4 h-4 text-gray-400" />
        }
    }

    const getStatusBadge = (status: string) => {
        const variants: Record<string, string> = {
            pendiente: 'bg-gray-500/10 text-gray-400 border-gray-500/20',
            depositado: 'bg-blue-500/10 text-blue-400 border-blue-500/20',
            acreditado: 'bg-emerald-500/10 text-emerald-400 border-emerald-500/20',
            rechazado: 'bg-red-500/10 text-red-400 border-red-500/20',
            endosado: 'bg-purple-500/10 text-purple-400 border-purple-500/20',
            anulado: 'bg-zinc-500/10 text-zinc-400 border-zinc-500/20',
        }
        return (
            <Badge variant="outline" className={variants[status] || variants.pendiente}>
                {status.toUpperCase()}
            </Badge>
        )
    }

    const formatDate = (dateStr: string) => {
        try {
            return new Intl.DateTimeFormat('es-AR', {
                day: 'numeric',
                month: 'long',
                hour: '2-digit',
                minute: '2-digit'
            }).format(new Date(dateStr))
        } catch (e) {
            return dateStr
        }
    }

    return (
        <Dialog open={isOpen} onOpenChange={onClose}>
            <DialogContent className="sm:max-w-[500px] bg-gray-950 border-gray-800 text-white p-0 overflow-hidden shadow-2xl">
                <DialogHeader className="p-6 bg-gray-900/50 border-b border-gray-800">
                    <DialogTitle className="flex items-center gap-2 text-xl font-bold tracking-tight">
                        <Clock className="w-5 h-5 text-blue-400" />
                        Historial del Cheque #{checkNumero}
                    </DialogTitle>
                </DialogHeader>

                <div className="p-6">
                    {loading ? (
                        <div className="flex flex-col items-center justify-center py-12 space-y-4">
                            <div className="w-8 h-8 border-2 border-blue-500 border-t-transparent rounded-full animate-spin"></div>
                            <p className="text-gray-400 text-sm italic">Rastreando movimientos...</p>
                        </div>
                    ) : history.length === 0 ? (
                        <div className="text-center py-12">
                            <Clock className="w-12 h-12 text-gray-800 mx-auto mb-4" />
                            <p className="text-gray-400">No se encontraron registros previos para este valor.</p>
                        </div>
                    ) : (
                        <ScrollArea className="h-[400px] pr-4">
                            <div className="relative space-y-8 before:absolute before:inset-0 before:ml-5 before:-translate-x-px before:h-full before:w-0.5 before:bg-gradient-to-b before:from-blue-500/50 before:via-gray-800 before:to-transparent">
                                {history.map((entry, index) => (
                                    <div key={entry.id} className="relative flex items-start gap-6 animate-in fade-in slide-in-from-left-4 duration-500" style={{ animationDelay: `${index * 50}ms` }}>
                                        <div className="absolute left-0 mt-1 flex h-10 w-10 items-center justify-center rounded-full bg-gray-900 border border-gray-800 shadow-xl z-10 transition-transform hover:scale-110">
                                            {getStatusIcon(entry.estado_nuevo)}
                                        </div>

                                        <div className="ml-12 flex-1 pt-1">
                                            <div className="flex flex-col md:flex-row md:items-center justify-between gap-2 mb-2">
                                                <div className="flex items-center gap-2">
                                                    {entry.estado_anterior && (
                                                        <>
                                                            {getStatusBadge(entry.estado_anterior)}
                                                            <ArrowRight className="w-3 h-3 text-gray-600" />
                                                        </>
                                                    )}
                                                    {getStatusBadge(entry.estado_nuevo)}
                                                </div>
                                                <span className="text-[10px] uppercase font-bold text-gray-500 flex items-center gap-1">
                                                    <Calendar className="w-3 h-3" />
                                                    {formatDate(entry.created_at)}
                                                </span>
                                            </div>

                                            <div className="bg-gray-900/40 border border-gray-800/50 rounded-xl p-3 hover:bg-gray-900/60 transition-colors">
                                                {entry.motivo && <p className="text-sm text-gray-300 mb-2 font-medium">{entry.motivo}</p>}
                                                <div className="flex items-center gap-4 text-[11px] text-gray-500">
                                                    <span className="flex items-center gap-1.5 bg-gray-800/50 px-2 py-0.5 rounded-full uppercase tracking-tighter font-bold">
                                                        <User className="w-3 h-3" />
                                                        {entry.usuario_id === 'system' || !entry.usuario_id ? 'SISTEMA' : 'OPERADOR'}
                                                    </span>
                                                    {entry.metadata?.cuenta_destino && (
                                                        <span className="flex items-center gap-1.5 bg-blue-500/10 text-blue-400 px-2 py-0.5 rounded-full">
                                                            <Landmark className="w-3 h-3" />
                                                            Cta: {entry.metadata.cuenta_destino}
                                                        </span>
                                                    )}
                                                </div>
                                            </div>
                                        </div>
                                    </div>
                                ))}
                            </div>
                        </ScrollArea>
                    )}
                </div>

                <div className="p-4 bg-gray-950/50 border-t border-gray-800 flex justify-end">
                    <button
                        onClick={onClose}
                        className="px-4 py-2 bg-gray-800 hover:bg-gray-700 text-white text-sm font-medium rounded-lg transition-all active:scale-95 shadow-lg"
                    >
                        Cerrar Registro
                    </button>
                </div>
            </DialogContent>
        </Dialog>
    )
}

'use client'

import { useState, useEffect, useCallback, useMemo } from 'react'
import { createClient } from '@/lib/supabase/client'
import { Card, CardContent, CardDescription, CardFooter, CardHeader, CardTitle } from '@/components/ui/card'
import { Input } from '@/components/ui/input'
import { Label } from '@/components/ui/label'
import { Button } from '@/components/ui/button'
import { PiggyBank, Save, Landmark, Plus, Loader2, CheckCircle2, Trash2, Brain, AlertTriangle, RotateCcw, RefreshCw, User, Settings } from 'lucide-react'
// Eliminados Dialog imports ya que no se usan más en esta pestaña

// Interfaces actualizadas
interface BankAccount {
    id?: string
    banco_nombre: string
    cbu: string
    saldo_inicial: number
    colchon_liquidez?: number
    limite_descubierto?: number
    mantenimiento_pactado?: number
    comision_cheque?: number
}

interface CompanyConfig {
    tna: number
    limite_descubierto: number
    modo_tasa: 'AUTOMATICO' | 'MANUAL'
    tasa_referencia_auto: 'PLAZO_FIJO' | 'BADLAR' | string
    colchon_liquidez: number
}

interface TaxRule {
    id: string
    patron_busqueda: string
    es_recuperable: boolean
    omitir_siempre: boolean
    estado: string
}

// interface BankAgreement deprecated in favor of BankAccount fields

export function CompanySettingsTab({ organizationId }: { organizationId: string }) {
    const [config, setConfig] = useState<CompanyConfig>({
        tna: 0.70,
        limite_descubierto: 0,
        modo_tasa: 'AUTOMATICO',
        tasa_referencia_auto: 'PLAZO_FIJO',
        colchon_liquidez: 0
    })

    // Removed global agreement state

    // Estado para Cuentas Bancarias
    const [accounts, setAccounts] = useState<BankAccount[]>([])
    const [editingAccountIndex, setEditingAccountIndex] = useState<number | null>(null)
    const [taxRules, setTaxRules] = useState<TaxRule[]>([])

    const [marketRates, setMarketRates] = useState<{ PLAZO_FIJO: number, BADLAR: number, bancos: Record<string, number>, updatedAt?: string }>({ PLAZO_FIJO: 0, BADLAR: 0, bancos: {} })
    const [loading, setLoading] = useState(true)
    const [saving, setSaving] = useState(false)
    const [success, setSuccess] = useState(false)
    const [syncingRate, setSyncingRate] = useState(false)

    // Estado para equipo
    const [members, setMembers] = useState<any[]>([])
    const [inviteEmail, setInviteEmail] = useState('')
    const [inviting, setInviting] = useState(false)

    const supabase = useMemo(() => createClient(), [])

    useEffect(() => {
        async function loadData() {
            if (!organizationId) {
                console.warn("CompanySettingsTab: No organizationId provided")
                setLoading(false)
                return
            }

            setLoading(true)

            try {
                // Ejecutar todas las consultas en paralelo
                const [
                    confRes,
                    accsRes,
                    marketRes,
                    rulesRes,
                    teamRes
                ] = await Promise.all([
                    supabase.from('configuracion_empresa').select('*').eq('organization_id', organizationId).maybeSingle(),
                    supabase.from('cuentas_bancarias').select('*').eq('organization_id', organizationId),
                    supabase.from('indices_mercado').select('tasa_plazo_fijo_30d, tasa_plazo_fijo, tasa_badlar, tasas_bancos, updated_at').order('fecha', { ascending: false }).limit(1).maybeSingle(),
                    supabase.from('tax_intelligence_rules').select('*').eq('organization_id', organizationId).order('created_at', { ascending: false }),
                    supabase.from('organization_members').select('id, role, user_id, created_at').eq('organization_id', organizationId)
                ])

                if (confRes.data) {
                    setConfig({
                        tna: confRes.data.tna,
                        limite_descubierto: confRes.data.limite_descubierto,
                        modo_tasa: confRes.data.modo_tasa || 'AUTOMATICO',
                        tasa_referencia_auto: confRes.data.tasa_referencia_auto || 'PLAZO_FIJO',
                        colchon_liquidez: confRes.data.colchon_liquidez || 0
                    })
                }

                // 3. Procesar Cuentas Bancarias
                if (accsRes.data && accsRes.data.length > 0) {
                    setAccounts(accsRes.data)
                } else {
                    setAccounts([{ banco_nombre: 'Banco Principal', cbu: '', saldo_inicial: 0, colchon_liquidez: 0, limite_descubierto: 0, mantenimiento_pactado: 0, comision_cheque: 0 }])
                }

                if (marketRes.data) {
                    setMarketRates({
                        PLAZO_FIJO: (marketRes.data.tasa_plazo_fijo_30d || marketRes.data.tasa_plazo_fijo || 0) > 1 ? (marketRes.data.tasa_plazo_fijo_30d || marketRes.data.tasa_plazo_fijo || 0) / 100 : (marketRes.data.tasa_plazo_fijo_30d || marketRes.data.tasa_plazo_fijo || 0),
                        BADLAR: (marketRes.data.tasa_badlar || 0) > 1 ? (marketRes.data.tasa_badlar || 0) / 100 : (marketRes.data.tasa_badlar || 0),
                        bancos: Object.fromEntries(
                            Object.entries(marketRes.data.tasas_bancos || {}).map(([b, t]: [string, any]) => [b, (t > 1 ? t / 100 : t)])
                        ),
                        updatedAt: marketRes.data.updated_at
                    })
                }

                // 5. Procesar Reglas de Impuestos
                if (rulesRes.data) {
                    setTaxRules(rulesRes.data)
                }

                // 6. Procesar Miembros del Equipo
                if (teamRes.data) {
                    setMembers(teamRes.data)
                }

            } catch (err) {
                console.error("Error loading settings data:", err)
            } finally {
                setLoading(false)
            }
        }

        loadData()
    }, [organizationId, supabase])

    const toggleTaxRule = async (ruleId: string, currentStatus: boolean) => {
        // We use the same API as the widget to ensure tags are synced
        const rule = taxRules.find(r => r.id === ruleId)
        if (!rule) return

        setSaving(true)
        try {
            const res = await fetch('/api/taxes/classify', {
                method: 'POST',
                body: JSON.stringify({
                    id: ruleId,
                    organization_id: organizationId,
                    es_recuperable: !currentStatus,
                    omitir_siempre: rule.omitir_siempre,
                    action: !currentStatus ? 'YES' : 'NO'
                })
            })

            if (res.ok) {
                setTaxRules(prev => prev.map(r => r.id === ruleId ? { ...r, es_recuperable: !currentStatus, estado: 'CLASIFICADO' } : r))
            }
        } catch (err) {
            console.error(err)
        } finally {
            setSaving(false)
        }
    }

    const deleteTaxRule = async (ruleId: string) => {
        if (!confirm('¿Seguro que quieres eliminar esta regla? El sistema volverá a detectarla si las transacciones siguen presentes.')) return

        setSaving(true)
        try {
            const { error } = await supabase.from('tax_intelligence_rules').delete().eq('id', ruleId)
            if (error) {
                console.error("Error eliminando regla:", error)
                alert("No se pudo eliminar la regla: " + error.message)
                return
            }
            setTaxRules(prev => prev.filter(r => r.id !== ruleId))
        } catch (err: any) {
            console.error(err)
            alert("Error de conexión al eliminar la regla.")
        } finally {
            setSaving(false)
        }
    }

    const handleSyncMarketRate = async () => {
        setSyncingRate(true)
        try {
            const res = await fetch('/api/market/sync', { method: 'POST' })
            const data = await res.json()
            if (data.success) {
                setMarketRates({
                    PLAZO_FIJO: data.tasa,
                    BADLAR: data.tasa_badlar || 0,
                    bancos: data.tasas_bancos || {},
                    updatedAt: data.updated_at
                })

                // Actualizamos la TNA actual según la referencia seleccionada
                let nuevaTna = data.tasa; // Default PROMEDIO
                if (config.tasa_referencia_auto === 'BADLAR') {
                    nuevaTna = data.tasa_badlar || 0;
                } else if (data.tasas_bancos && data.tasas_bancos[config.tasa_referencia_auto]) {
                    nuevaTna = data.tasas_bancos[config.tasa_referencia_auto];
                }

                setConfig(prev => ({ ...prev, tna: nuevaTna, modo_tasa: 'AUTOMATICO' }))
                alert(`Tasas actualizadas correctamente.`)
            } else {
                throw new Error(data.error || 'Error al sincronizar tasa')
            }
        } catch (err: any) {
            console.error(err)
            alert("No se pudo obtener la tasa del mercado: " + err.message)
        } finally {
            setSyncingRate(false)
        }
    }

    const handleFullReset = async () => {
        if (!confirm('¡PELIGRO! Esto eliminará TODAS las transacciones, comprobantes e historial de importaciones de tu organización. Esta acción NO se puede deshacer. ¿Estás seguro?')) return
        if (!confirm('Confirmación final: ¿Realmente quieres BORRAR TODO?')) return

        setSaving(true)
        try {
            const res = await fetch('/api/data/purge', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ mode: 'full_reset' })
            })
            if (res.ok) {
                alert('Reinicio completo exitoso. La página se recargará.')
                window.location.reload()
            } else {
                const err = await res.json()
                alert('Error al reiniciar: ' + (err.details || err.error))
            }
        } catch (err) {
            alert('Error de conexión al purgar datos.')
        } finally {
            setSaving(false)
        }
    }

    const handleCleanOrphans = async () => {
        if (!confirm('Esto eliminará todas las transacciones sin archivo asociado (huérfanas) que pueden estar causando duplicados. ¿Continuar?')) return

        setSaving(true)
        try {
            const res = await fetch('/api/data/purge', { method: 'POST' })
            if (res.ok) {
                alert('Limpieza de huérfanos completada.')
            } else {
                const err = await res.json()
                alert('Error en la limpieza: ' + (err.details || err.error))
            }
        } catch (err) {
            alert('Error de conexión.')
        } finally {
            setSaving(false)
        }
    }

    const handleDeleteAllClients = async () => {
        if (!confirm('¡ATENCIÓN! Esto eliminará TODOS los clientes de tu organización. Esta acción NO se puede deshacer. ¿Seguro?')) return
        if (!confirm('Confirmación final: ¿Realmente quieres borrar todos los clientes?')) return

        setSaving(true)
        try {
            const res = await fetch('/api/data/purge', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ mode: 'delete_clients' })
            })
            if (res.ok) {
                alert('Todos los clientes han sido eliminados.')
            } else {
                const err = await res.json()
                alert('Error al eliminar clientes: ' + (err.details || err.error))
            }
        } catch (err) {
            alert('Error de conexión.')
        } finally {
            setSaving(false)
        }
    }

    const handleDeleteAllSuppliers = async () => {
        if (!confirm('¡ATENCIÓN! Esto eliminará TODOS los proveedores de tu organización. Esta acción NO se puede deshacer. ¿Seguro?')) return
        if (!confirm('Confirmación final: ¿Realmente quieres borrar todos los proveedores?')) return

        setSaving(true)
        try {
            const res = await fetch('/api/data/purge', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ mode: 'delete_suppliers' })
            })
            if (res.ok) {
                alert('Todos los proveedores han sido eliminados.')
            } else {
                const err = await res.json()
                alert('Error al eliminar proveedores: ' + (err.details || err.error))
            }
        } catch (err) {
            alert('Error de conexión.')
        } finally {
            setSaving(false)
        }
    }

    const handleSave = async () => {
        setSaving(true)
        setSuccess(false)

        try {
            console.log("Iniciando guardado de configuración para organización:", organizationId)

            // 1. Guardar Config General
            const { error: errorConfig } = await supabase.from('configuracion_empresa').upsert({
                organization_id: organizationId,
                tna: config.tna,
                limite_descubierto: config.limite_descubierto,
                modo_tasa: config.modo_tasa,
                tasa_referencia_auto: config.tasa_referencia_auto,
                colchon_liquidez: config.colchon_liquidez,
                updated_at: new Date().toISOString()
            }, { onConflict: 'organization_id' })

            if (errorConfig) throw new Error("Error en Configuración Empresa: " + errorConfig.message)

            // 2. Eliminar legacy convenios si es necesario (opcional, por ahora lo dejamos)

            // 3. GUARDAR CUENTAS
            const accountsWithId = accounts
                .filter(acc => acc.banco_nombre.trim() !== '' && acc.id)
                .map(acc => ({
                    id: acc.id,
                    organization_id: organizationId,
                    banco_nombre: acc.banco_nombre,
                    cbu: acc.cbu,
                    saldo_inicial: acc.saldo_inicial,
                    colchon_liquidez: acc.colchon_liquidez || 0,
                    limite_descubierto: acc.limite_descubierto || 0,
                    mantenimiento_pactado: acc.mantenimiento_pactado || 0,
                    comision_cheque: acc.comision_cheque || 0,
                    updated_at: new Date().toISOString()
                }))

            const accountsNew = accounts
                .filter(acc => acc.banco_nombre.trim() !== '' && !acc.id)
                .map(acc => ({
                    organization_id: organizationId,
                    banco_nombre: acc.banco_nombre,
                    cbu: acc.cbu,
                    saldo_inicial: acc.saldo_inicial,
                    colchon_liquidez: acc.colchon_liquidez || 0,
                    limite_descubierto: acc.limite_descubierto || 0,
                    mantenimiento_pactado: acc.mantenimiento_pactado || 0,
                    comision_cheque: acc.comision_cheque || 0,
                    updated_at: new Date().toISOString()
                }))

            let results: any[] = []

            if (accountsWithId.length > 0) {
                console.log("Upserting existing accounts:", accountsWithId)
                const { data, error } = await supabase
                    .from('cuentas_bancarias')
                    .upsert(accountsWithId)
                    .select()
                if (error) throw new Error("Error actualizando Cuentas Bancarias: " + error.message)
                if (data) results = [...results, ...data]
            }

            if (accountsNew.length > 0) {
                console.log("Inserting new accounts:", accountsNew)
                const { data, error } = await supabase
                    .from('cuentas_bancarias')
                    .insert(accountsNew)
                    .select()
                if (error) throw new Error("Error insertando Cuentas Bancarias: " + error.message)
                if (data) results = [...results, ...data]
            }

            if (results.length > 0) {
                console.log("Cuentas guardadas:", results)
                // Reconstruimos la lista para mantener el orden visual
                const updatedAccounts = accounts.map(acc => {
                    if (acc.id) {
                        return results.find(r => r.id === acc.id) || acc
                    } else {
                        // Match por nombre para las nuevas si hay coincidencia
                        return results.find(r => r.banco_nombre === acc.banco_nombre && !accountsWithId.some(aw => aw.id === r.id)) || acc
                    }
                })
                setAccounts(updatedAccounts)
            }

            setSuccess(true)
            setTimeout(() => setSuccess(false), 3000)
        } catch (err: any) {
            console.error("Error crítico durante el guardado:", err)
            alert(err.message || "Ocurrió un error inesperado al guardar.")
        } finally {
            setSaving(false)
        }
    }

    const updateAccount = (index: number, field: keyof BankAccount, value: any) => {
        const newAccounts = [...accounts]
        newAccounts[index] = { ...newAccounts[index], [field]: value }
        setAccounts(newAccounts)
    }

    const removeAccount = async (index: number) => {
        const accountToDelete = accounts[index]
        if (accountToDelete.id) {
            setSaving(true)
            const { error } = await supabase.from('cuentas_bancarias').delete().eq('id', accountToDelete.id)
            setSaving(false)
            if (error) {
                console.error("Error eliminando cuenta:", error)
                return
            }
        }
        const newAccounts = accounts.filter((_, i) => i !== index)
        // No permitir quedar con 0 cuentas visualmente si el usuario quiere agregar luego
        if (newAccounts.length === 0) {
            setAccounts([{ banco_nombre: '', cbu: '', saldo_inicial: 0, colchon_liquidez: 0, limite_descubierto: 0, mantenimiento_pactado: 0, comision_cheque: 0 }])
        } else {
            setAccounts(newAccounts)
        }
    }

    const handleInvite = async () => {
        if (!inviteEmail.trim()) return
        setInviting(true)
        try {
            const res = await fetch('/api/orgs/invite', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    email: inviteEmail,
                    organizationId: organizationId,
                    role: 'member'
                })
            })
            const data = await res.json()
            if (res.ok) {
                alert('Invitación enviada con éxito a ' + inviteEmail)
                setInviteEmail('')
            } else {
                alert('Error: ' + data.error)
            }
        } catch (err) {
            alert('Error de conexión al enviar invitación')
        } finally {
            setInviting(false)
        }
    }

    const removeMember = async (memberId: string) => {
        if (!confirm('¿Seguro que quieres quitar a este miembro de la organización?')) return
        setSaving(true)
        try {
            const { error } = await supabase.from('organization_members').delete().eq('id', memberId)
            if (error) throw error
            setMembers(prev => prev.filter(m => m.id !== memberId))
        } catch (err: any) {
            alert('Error al eliminar miembro: ' + err.message)
        } finally {
            setSaving(false)
        }
    }

    if (loading) return <div className="p-8 text-center text-gray-500">
        < Loader2 className="h-8 w-8 animate-spin mx-auto text-emerald-500 mb-4" />
        Cargando configuración...
    </div >

    return (
        <div className="space-y-6 max-w-5xl mx-auto pb-20">
            <div className="flex flex-col gap-2">
                <h2 className="text-2xl font-bold tracking-tight text-white uppercase italic">Configuración Financiera</h2>
                <p className="text-gray-400">Define tus saldos iniciales y parámetros para que la IA calcule correctamente.</p>
            </div>

            <div className="grid gap-6 md:grid-cols-2">

                {/* NUEVA TARJETA: SALDOS INICIALES */}
                <Card className="bg-gray-900 border-gray-800 md:col-span-2 border-l-4 border-l-emerald-500">
                    <CardHeader className="bg-emerald-500/5">
                        <CardTitle className="flex items-center gap-2 text-white font-black italic tracking-tighter">
                            <Landmark className="h-5 w-5 text-emerald-500" />
                            CUENTAS BANCARIAS & SALDOS INICIALES
                        </CardTitle>
                        <CardDescription className="text-gray-400">
                            Ingresa el saldo real de tus cuentas al día de hoy para arrancar la conciliación.
                        </CardDescription>
                    </CardHeader>
                    <CardContent className="space-y-6 pt-6">
                        {accounts.map((acc, idx) => (
                            <div key={idx} className="relative flex flex-col gap-6 p-6 bg-gray-950/50 rounded-2xl border border-gray-800 transition-all hover:border-emerald-500/30 group">
                                <Button
                                    variant="ghost"
                                    size="icon"
                                    onClick={() => removeAccount(idx)}
                                    className="absolute -right-2 -top-2 h-8 w-8 rounded-full bg-red-500/10 text-red-500 opacity-0 group-hover:opacity-100 transition-opacity hover:bg-red-500 hover:text-white border border-red-500/20 z-10"
                                >
                                    <Trash2 className="h-4 w-4" />
                                </Button>

                                {/* Sección 1: Datos Básicos */}
                                <div className="grid grid-cols-1 md:grid-cols-12 gap-6">
                                    <div className="md:col-span-4 space-y-2">
                                        <Label className="text-[10px] font-black uppercase text-gray-500 tracking-widest h-4 flex items-center">Banco / Identificador</Label>
                                        <Input
                                            value={acc.banco_nombre}
                                            onChange={(e) => updateAccount(idx, 'banco_nombre', e.target.value)}
                                            className="bg-gray-900 border-gray-800 focus:border-emerald-500/50 text-white h-11 text-sm"
                                            placeholder="Ej: Galicia Principal"
                                        />
                                    </div>
                                    <div className="md:col-span-4 space-y-2">
                                        <Label className="text-[10px] text-emerald-400 font-black uppercase tracking-widest h-4 flex items-center">Saldo Inicial (Arranque)</Label>
                                        <div className="relative">
                                            <span className="absolute left-3 top-3 text-gray-600 font-bold">$</span>
                                            <Input
                                                type="number"
                                                value={acc.saldo_inicial}
                                                onChange={(e) => {
                                                    const val = parseFloat(e.target.value)
                                                    updateAccount(idx, 'saldo_inicial', isNaN(val) ? 0 : val)
                                                }}
                                                className="pl-8 bg-gray-900 border-gray-800 text-white font-mono h-11 text-sm"
                                            />
                                        </div>
                                    </div>
                                    <div className="md:col-span-4 space-y-2">
                                        <Label className="text-[10px] font-black uppercase text-gray-500 tracking-widest h-4 flex items-center">CBU / ALIAS</Label>
                                        <Input
                                            value={acc.cbu}
                                            onChange={(e) => updateAccount(idx, 'cbu', e.target.value)}
                                            className="bg-gray-900 border-gray-800 focus:border-emerald-500/50 text-white font-mono h-11 text-sm"
                                            placeholder="22 dígitos"
                                        />
                                    </div>
                                </div>

                                {/* Sección 2: Acuerdos Bancarios (Lo que el usuario pidió ver directo) */}
                                <div className="pt-6 border-t border-gray-800/50">
                                    <div className="flex items-center gap-2 mb-4">
                                        <Settings className="w-3 h-3 text-emerald-500/50" />
                                        <span className="text-[10px] font-black text-gray-600 uppercase tracking-[0.2em]">Acuerdos Bancarios & Límites</span>
                                    </div>
                                    <div className="grid grid-cols-1 md:grid-cols-12 gap-6">
                                        <div className="md:col-span-3 space-y-2">
                                            <Label className="text-[10px] font-bold uppercase text-gray-400 tracking-widest h-4 flex items-center">Colchón de Liquidez</Label>
                                            <div className="relative">
                                                <span className="absolute left-3 top-3 text-gray-600 font-bold">$</span>
                                                <Input
                                                    type="number"
                                                    value={acc.colchon_liquidez}
                                                    onChange={(e) => updateAccount(idx, 'colchon_liquidez', parseFloat(e.target.value) || 0)}
                                                    className="pl-7 bg-gray-900/50 border-gray-800 text-white font-mono text-sm h-11"
                                                />
                                            </div>
                                            <p className="text-[9px] text-gray-600 italic leading-tight">Monto mínimo a mantener.</p>
                                        </div>

                                        <div className="md:col-span-3 space-y-2">
                                            <Label className="text-[10px] font-bold uppercase text-gray-400 tracking-widest h-4 flex items-center">Límite Descubierto</Label>
                                            <div className="relative">
                                                <span className="absolute left-3 top-3 text-gray-600 font-bold">$</span>
                                                <Input
                                                    type="number"
                                                    value={acc.limite_descubierto}
                                                    onChange={(e) => updateAccount(idx, 'limite_descubierto', parseFloat(e.target.value) || 0)}
                                                    className="pl-7 bg-gray-900/50 border-gray-800 text-white font-mono text-sm h-11"
                                                />
                                            </div>
                                        </div>

                                        <div className="md:col-span-3 space-y-2">
                                            <Label className="text-[10px] font-bold uppercase text-gray-400 tracking-widest h-4 flex items-center">Mantenimiento ($/mes)</Label>
                                            <Input
                                                type="number"
                                                value={acc.mantenimiento_pactado}
                                                onChange={(e) => updateAccount(idx, 'mantenimiento_pactado', parseFloat(e.target.value) || 0)}
                                                className="bg-gray-900/50 border-gray-800 text-white font-mono text-sm h-11"
                                            />
                                        </div>

                                        <div className="md:col-span-3 space-y-2">
                                            <Label className="text-[10px] font-bold uppercase text-gray-400 tracking-widest h-4 flex items-center">Comisión Cheque (%)</Label>
                                            <div className="relative">
                                                <Input
                                                    type="number"
                                                    step="0.01"
                                                    value={acc.comision_cheque}
                                                    onChange={(e) => updateAccount(idx, 'comision_cheque', parseFloat(e.target.value) || 0)}
                                                    className="bg-gray-900/50 border-gray-800 text-white font-mono text-sm pr-6 h-11"
                                                />
                                                <span className="absolute right-2 top-3 text-gray-600 font-bold">%</span>
                                            </div>
                                        </div>
                                    </div>
                                </div>
                            </div>
                        ))}
                        <Button variant="outline" size="sm" onClick={() => setAccounts([...accounts, { banco_nombre: '', cbu: '', saldo_inicial: 0 }])} className="w-full border-dashed border-gray-700 text-gray-400 hover:text-white hover:bg-gray-800 hover:border-emerald-500/50 transition-all">
                            <Plus className="h-4 w-4 mr-2" /> AGREGAR OTRA CUENTA
                        </Button>
                    </CardContent>
                </Card>

                {/* PARÁMETROS DE MERCADO (Existente) */}
                <Card className="bg-gray-900/30 border-gray-800 backdrop-blur-sm overflow-hidden border-l-4 border-l-blue-500 shadow-2xl md:col-span-2">
                    <CardHeader className="border-b border-gray-800/50 bg-gray-900/50 pb-4">
                        <div className="flex items-center gap-3">
                            <div className="p-2 bg-blue-500/10 rounded-lg">
                                <PiggyBank className="w-5 h-5 text-blue-400" />
                            </div>
                            <div>
                                <CardTitle className="text-xl font-black tracking-tight text-white uppercase italic">Costo de Oportunidad</CardTitle>
                                <CardDescription className="text-gray-400 text-xs">Parámetros para calcular el rendimiento del dinero ocioso.</CardDescription>
                            </div>
                        </div>
                    </CardHeader>

                    <CardContent className="p-0">
                        <div className="grid grid-cols-1 md:grid-cols-5 divide-x divide-gray-800">
                            {/* Columna Izquierda: Control Actual */}
                            <div className="md:col-span-2 p-6 space-y-8 bg-gray-950/20">
                                <div>
                                    <div className="flex justify-between items-center mb-4">
                                        <Label className="text-[10px] font-black text-gray-500 uppercase tracking-[0.2em]">Modo de Tasa</Label>
                                        <div className="flex bg-gray-950 rounded-lg p-1 border border-gray-800">
                                            <button
                                                onClick={() => setConfig({ ...config, modo_tasa: 'AUTOMATICO' })}
                                                className={`px-3 py-1 text-[10px] font-black rounded transition-all ${config.modo_tasa === 'AUTOMATICO' ? 'bg-blue-600 text-white shadow-lg' : 'text-gray-500 hover:text-blue-400'}`}
                                            >
                                                AUTO
                                            </button>
                                            <button
                                                onClick={() => setConfig({ ...config, modo_tasa: 'MANUAL' })}
                                                className={`px-3 py-1 text-[10px] font-black rounded transition-all ${config.modo_tasa === 'MANUAL' ? 'bg-blue-600 text-white shadow-lg' : 'text-gray-500 hover:text-blue-400'}`}
                                            >
                                                MANUAL
                                            </button>
                                        </div>
                                    </div>

                                    <Label className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-2 block">TNA Aplicada (%)</Label>
                                    <div className="relative mb-4">
                                        <Input
                                            type="number"
                                            value={(config.tna * 100).toFixed(2)}
                                            onChange={(e) => {
                                                const val = parseFloat(e.target.value)
                                                setConfig({ ...config, tna: (isNaN(val) ? 0 : val) / 100, modo_tasa: 'MANUAL' })
                                            }}
                                            disabled={config.modo_tasa === 'AUTOMATICO' && syncingRate}
                                            className={`bg-gray-950 border-gray-800 text-3xl h-20 font-mono text-center text-white transition-all ${config.modo_tasa === 'AUTOMATICO' ? 'border-blue-500/50 text-blue-400 ring-2 ring-blue-500/10' : 'focus:border-blue-500'}`}
                                        />
                                        <span className={`absolute right-6 top-6 text-2xl font-bold ${config.modo_tasa === 'AUTOMATICO' ? 'text-blue-500' : 'text-gray-600'}`}>%</span>
                                    </div>

                                    {config.modo_tasa === 'AUTOMATICO' && (
                                        <div className="flex items-center gap-2 p-3 bg-blue-500/5 rounded-lg border border-blue-500/20 mb-4 animate-in fade-in slide-in-from-top-2">
                                            <CheckCircle2 className="w-4 h-4 text-blue-500" />
                                            <p className="text-[11px] text-blue-100 font-medium italic">
                                                Sincronizado con {
                                                    config.tasa_referencia_auto === 'BADLAR' ? 'BADLAR' :
                                                        config.tasa_referencia_auto === 'PLAZO_FIJO' ? 'Promedio Mercado' :
                                                            (() => {
                                                                const name = config.tasa_referencia_auto as string;
                                                                if (name.includes('NACION')) return 'BANCO NACIÓN';
                                                                if (name.includes('SANTANDER')) return 'SANTANDER';
                                                                if (name.includes('GALICIA')) return 'GALICIA';
                                                                if (name.includes('PROVINCIA')) return 'BANCO PROVINCIA';
                                                                if (name.includes('BBVA')) return 'BBVA';
                                                                if (name.includes('MACRO')) return 'MACRO';
                                                                if (name.includes('CREDICOOP')) return 'CREDICOOP';
                                                                if (name.includes('CIUDAD')) return 'BANCO CIUDAD';
                                                                return name.replace('BANCO ', '').replace(' S.A.', '').replace('ARGENTINA', '').trim();
                                                            })()
                                                }
                                            </p>
                                        </div>
                                    )}

                                    <Button
                                        onClick={handleSyncMarketRate}
                                        disabled={syncingRate}
                                        variant="outline"
                                        className="w-full h-12 bg-gray-900 border-gray-800 hover:bg-gray-800 hover:text-blue-400 transition-all font-bold text-xs gap-2 group"
                                    >
                                        {syncingRate ? <Loader2 className="h-4 w-4 animate-spin" /> : <RefreshCw className={`h-4 w-4 transition-transform ${syncingRate ? '' : 'group-hover:rotate-180'}`} />}
                                        ACTUALIZAR TASAS DE MERCADO
                                    </Button>

                                    {marketRates.updatedAt && (
                                        <div className="mt-4 text-center animate-in fade-in zoom-in duration-500">
                                            <p className="text-[9px] text-gray-500 font-black uppercase tracking-[0.2em] mb-1">
                                                Última actualización de TNA
                                            </p>
                                            <p className="text-[10px] text-blue-400/70 font-mono font-bold">
                                                {
                                                    new Date(marketRates.updatedAt).toLocaleString('es-AR', {
                                                        timeZone: 'America/Argentina/Buenos_Aires',
                                                        day: '2-digit',
                                                        month: '2-digit',
                                                        year: 'numeric',
                                                        hour: '2-digit',
                                                        minute: '2-digit',
                                                        hour12: true
                                                    })
                                                } ART
                                            </p>
                                        </div>
                                    )}
                                </div>
                            </div>

                            {/* Columna Derecha: Selección de Referencia */}
                            <div className="md:col-span-3 p-6 flex flex-col h-full bg-black/20">
                                <div className="flex items-center justify-between mb-4">
                                    <Label className="text-[10px] font-black text-gray-500 uppercase tracking-[0.2em]">Opciones de Referencia</Label>
                                    <span className="text-[9px] text-gray-600 font-bold">VALORES DEL DÍA</span>
                                </div>

                                <div className="flex-1 overflow-y-auto pr-2 space-y-2 custom-scrollbar max-h-[320px]">
                                    {/* Principales Índices */}
                                    <div className="grid grid-cols-2 gap-2 mb-4">
                                        <button
                                            onClick={() => setConfig({ ...config, tasa_referencia_auto: 'PLAZO_FIJO', tna: marketRates.PLAZO_FIJO, modo_tasa: 'AUTOMATICO' })}
                                            className={`flex flex-col items-center justify-center p-4 rounded-xl border transition-all ${config.tasa_referencia_auto === 'PLAZO_FIJO' ? 'bg-emerald-500/10 border-emerald-500/50 text-emerald-100 ring-1 ring-emerald-500/20 shadow-[0_5px_15px_-5px_rgba(16,185,129,0.3)]' : 'bg-gray-900 border-gray-800 hover:border-gray-700 text-gray-400'}`}
                                        >
                                            <span className="text-[9px] font-black uppercase opacity-60 mb-1">PROMEDIO PF</span>
                                            <span className="text-xl font-mono font-bold">
                                                {((marketRates.PLAZO_FIJO * 100) % 1 === 0) ? (marketRates.PLAZO_FIJO * 100).toFixed(0) : (marketRates.PLAZO_FIJO * 100).toFixed(2)}%
                                            </span>
                                        </button>

                                        <button
                                            onClick={() => setConfig({ ...config, tasa_referencia_auto: 'BADLAR', tna: marketRates.BADLAR, modo_tasa: 'AUTOMATICO' })}
                                            className={`flex flex-col items-center justify-center p-4 rounded-xl border transition-all ${config.tasa_referencia_auto === 'BADLAR' ? 'bg-blue-500/10 border-blue-500/50 text-blue-100 ring-1 ring-blue-500/20 shadow-[0_5px_15px_-5px_rgba(59,130,246,0.3)]' : 'bg-gray-900 border-gray-800 hover:border-gray-700 text-gray-400'}`}
                                        >
                                            <span className="text-[9px] font-black uppercase opacity-60 mb-1">BADLAR BCRA</span>
                                            <span className="text-xl font-mono font-bold">
                                                {((marketRates.BADLAR * 100) % 1 === 0) ? (marketRates.BADLAR * 100).toFixed(0) : (marketRates.BADLAR * 100).toFixed(2)}%
                                            </span>
                                        </button>
                                    </div>

                                    {/* Bancos Individuales */}
                                    <div className="space-y-1.5 pt-2 border-t border-gray-800/50">
                                        <p className="text-[9px] font-bold text-gray-600 uppercase tracking-widest mb-3">Principales Entidades</p>
                                        {Object.entries(marketRates.bancos).length > 0 ? (
                                            Object.entries(marketRates.bancos).map(([banco, tasa]) => (
                                                <button
                                                    key={banco}
                                                    onClick={() => setConfig({ ...config, tasa_referencia_auto: banco as any, tna: tasa, modo_tasa: 'AUTOMATICO' })}
                                                    className={`flex items-center justify-between w-full p-3 rounded-lg border transition-all ${config.tasa_referencia_auto === banco ? 'bg-amber-500/10 border-amber-500/50 text-amber-100' : 'bg-gray-900/30 border-gray-800/40 hover:border-gray-700 text-gray-500'}`}
                                                >
                                                    <span className="text-xs font-bold uppercase truncate max-w-[150px]">
                                                        {(() => {
                                                            if (banco.includes('NACION')) return 'BANCO NACIÓN';
                                                            if (banco.includes('SANTANDER')) return 'SANTANDER';
                                                            if (banco.includes('GALICIA')) return 'GALICIA';
                                                            if (banco.includes('PROVINCIA')) return 'BANCO PROVINCIA';
                                                            if (banco.includes('BBVA')) return 'BBVA';
                                                            if (banco.includes('MACRO')) return 'MACRO';
                                                            if (banco.includes('CREDICOOP')) return 'CREDICOOP';
                                                            if (banco.includes('CIUDAD')) return 'BANCO CIUDAD';
                                                            return banco.replace('BANCO ', '').replace(' S.A.', '').replace('ARGENTINA', '').trim();
                                                        })()}
                                                    </span>
                                                    <div className="flex items-center gap-3">
                                                        <span className="text-sm font-mono font-bold">
                                                            {((tasa * 100) % 1 === 0) ? (tasa * 100).toFixed(0) : (tasa * 100).toFixed(2)}%
                                                        </span>
                                                        <div className={`w-2 h-2 rounded-full ${config.tasa_referencia_auto === banco ? 'bg-amber-500 animate-pulse' : 'bg-transparent'}`} />
                                                    </div>
                                                </button>
                                            ))
                                        ) : (
                                            <div className="text-center py-8 px-4 rounded-xl border border-dashed border-gray-800 opacity-50">
                                                <p className="text-[10px] text-gray-500 italic">No hay datos de entidades disponibles. Pulsa "Actualizar" para sincronizar.</p>
                                            </div>
                                        )}
                                    </div>
                                </div>
                            </div>
                        </div>
                    </CardContent>
                </Card>

                {/* ACUERDOS (Moved to per-account) */}

                {/* NUEVA TARJETA: REGLAS DE IMPUESTOS */}
                <Card className="bg-gray-900 border-gray-800 md:col-span-2 border-l-4 border-l-purple-500">
                    <CardHeader className="bg-purple-500/5">
                        <CardTitle className="flex items-center gap-2 text-white font-black italic tracking-tighter uppercase">
                            <Brain className="h-5 w-5 text-purple-500" />
                            Reglas de Impuestos (Aprendizaje)
                        </CardTitle>
                        <CardDescription className="text-gray-400">
                            Gestiona cómo BiFlow clasifica los impuestos detectados en tus extractos.
                        </CardDescription>
                    </CardHeader>
                    <CardContent className="pt-6">
                        {taxRules.length > 0 ? (
                            <div className="overflow-x-auto">
                                <table className="w-full text-left text-sm">
                                    <thead>
                                        <tr className="border-b border-gray-800 text-[10px] uppercase text-gray-500 font-bold">
                                            <th className="pb-3 pl-2">Concepto Detectado</th>
                                            <th className="pb-3">Estado</th>
                                            <th className="pb-3">¿Es Recuperable?</th>
                                            <th className="pb-3 text-right pr-2">Acciones</th>
                                        </tr>
                                    </thead>
                                    <tbody className="divide-y divide-gray-800">
                                        {taxRules.map((rule: any) => (
                                            <tr key={rule.id} className="group hover:bg-white/5 transition-colors">
                                                <td className="py-4 pl-2 font-mono text-xs text-white max-w-[300px] truncate">
                                                    <div className="flex flex-col">
                                                        <span>{rule.patron_busqueda}</span>
                                                        <span className="text-[9px] text-gray-500 uppercase">{rule.categoria || 'impuesto'}</span>
                                                    </div>
                                                </td>
                                                <td className="py-4 text-[10px] font-bold">
                                                    <span className={`px-2 py-0.5 rounded-full ${rule.estado === 'PENDIENTE' ? 'bg-amber-500/10 text-amber-500 animate-pulse' : rule.omitir_siempre ? 'bg-gray-800 text-gray-400' : 'bg-purple-500/10 text-purple-400'}`}>
                                                        {rule.estado === 'PENDIENTE' ? 'NUEVO' : rule.omitir_siempre ? 'IGNORADO' : 'CLASIFICADO'}
                                                    </span>
                                                </td>
                                                <td className="py-4">
                                                    <button
                                                        onClick={() => toggleTaxRule(rule.id, rule.es_recuperable)}
                                                        className={`px-3 py-1 rounded text-[10px] font-black transition-all ${rule.es_recuperable ? 'bg-emerald-600 text-white shadow-lg shadow-emerald-500/20' : 'bg-gray-800 text-gray-400'}`}
                                                    >
                                                        {rule.es_recuperable
                                                            ? (rule.categoria === 'servicio' ? 'SÍ (IVA RECO)' : 'SÍ (CRÉDITO FISCAL)')
                                                            : (rule.categoria === 'servicio' ? 'NO (GASTO FINAL)' : 'NO (COSTO FISCAL)')}
                                                    </button>
                                                </td>
                                                <td className="py-4 text-right pr-2">
                                                    <Button
                                                        variant="ghost"
                                                        size="icon"
                                                        onClick={() => deleteTaxRule(rule.id)}
                                                        className="h-8 w-8 text-gray-500 hover:text-red-400 opacity-0 group-hover:opacity-100 transition-opacity"
                                                    >
                                                        <Trash2 className="h-4 w-4" />
                                                    </Button>
                                                </td>
                                            </tr>
                                        ))}
                                    </tbody>
                                </table>
                            </div>
                        ) : (
                            <div className="text-center py-8 text-gray-500 italic text-sm">
                                No hay reglas guardadas aún. El sistema aprenderá a medida que clasifiques impuestos en el Centro de Auditoría.
                            </div>
                        )}
                    </CardContent>
                </Card>

                {/* NUEVA TARJETA: GESTIÓN DE EQUIPO */}
                <Card className="bg-gray-900 border-gray-800 md:col-span-2 border-l-4 border-l-orange-500">
                    <CardHeader className="bg-orange-500/5">
                        <CardTitle className="flex items-center gap-2 text-white font-black italic tracking-tighter uppercase">
                            <User className="h-5 w-5 text-orange-500" />
                            Gestión de Equipo
                        </CardTitle>
                        <CardDescription className="text-gray-400">
                            Invita a otros usuarios a colaborar en esta organización.
                        </CardDescription>
                    </CardHeader>
                    <CardContent className="pt-6 space-y-6">
                        <div className="flex gap-4">
                            <div className="flex-1">
                                <Input
                                    type="email"
                                    placeholder="email@colega.com"
                                    value={inviteEmail}
                                    onChange={(e) => setInviteEmail(e.target.value)}
                                    className="bg-gray-950 border-gray-800 text-white"
                                />
                            </div>
                            <Button
                                onClick={handleInvite}
                                disabled={inviting || !inviteEmail}
                                className="bg-orange-600 hover:bg-orange-500 text-white font-bold"
                            >
                                {inviting ? <Loader2 className="h-4 w-4 animate-spin" /> : <Plus className="h-4 w-4 mr-2" />}
                                INVITAR
                            </Button>
                        </div>

                        <div className="mt-6">
                            <h4 className="text-xs font-bold uppercase text-gray-500 mb-4 tracking-widest">Miembros Actuales</h4>
                            <div className="grid gap-2">
                                {members.map((member) => (
                                    <div key={member.id} className="flex items-center justify-between p-3 bg-gray-950/50 rounded-lg border border-gray-800 group">
                                        <div className="flex items-center gap-3">
                                            <div className="h-8 w-8 rounded-full bg-gray-800 flex items-center justify-center text-xs font-bold text-gray-400">
                                                {member.role === 'owner' ? '★' : 'U'}
                                            </div>
                                            <div>
                                                <p className="text-sm font-medium text-white">Usuario ID: {member.user_id.substring(0, 8)}...</p>
                                                <p className="text-[10px] text-gray-500 uppercase font-bold tracking-tighter">{member.role}</p>
                                            </div>
                                        </div>
                                        {member.role !== 'owner' && (
                                            <Button
                                                variant="ghost"
                                                size="icon"
                                                onClick={() => removeMember(member.id)}
                                                className="h-8 w-8 text-gray-500 hover:text-red-400 opacity-0 group-hover:opacity-100 transition-opacity"
                                            >
                                                <Trash2 className="h-4 w-4" />
                                            </Button>
                                        )}
                                    </div>
                                ))}
                            </div>
                        </div>
                    </CardContent>
                </Card>
            </div >

            {/* SECCIÓN DE MANTENIMIENTO & EMERGENCIA */}
            < Card className="bg-gray-900 border-gray-800 md:col-span-2 border-l-4 border-l-red-500/50" >
                <CardHeader className="bg-red-500/5">
                    <CardTitle className="flex items-center gap-2 text-white font-black italic tracking-tighter uppercase">
                        <AlertTriangle className="h-5 w-5 text-red-500" />
                        Mantenimiento y Emergencia
                    </CardTitle>
                    <CardDescription className="text-gray-400">
                        Herramientas avanzadas para resolver inconsistencias o reiniciar datos.
                    </CardDescription>
                </CardHeader>
                <CardContent className="pt-6 space-y-6">
                    <div className="flex flex-col md:flex-row items-center justify-between gap-4 p-4 bg-gray-950/50 rounded-xl border border-gray-800">
                        <div className="space-y-1">
                            <p className="text-white font-bold text-sm">Limpiar Registros Huérfanos</p>
                            <p className="text-[10px] text-gray-500">Elimina transacciones duplicadas que no tienen un archivo de importación asociado.</p>
                        </div>
                        <Button
                            variant="outline"
                            onClick={handleCleanOrphans}
                            disabled={saving}
                            className="border-red-500/20 hover:bg-red-500/10 text-red-400 font-bold text-xs"
                        >
                            {saving ? <Loader2 className="animate-spin mr-2 h-3.5 w-3.5" /> : <Trash2 className="mr-2 h-3.5 w-3.5" />}
                            Limpiar Huérfanos
                        </Button>
                    </div>

                    <div className="flex flex-col md:flex-row items-center justify-between gap-4 p-4 bg-red-500/10 rounded-xl border border-red-500/20">
                        <div className="space-y-1">
                            <p className="text-white font-bold text-sm uppercase">Reinicio Total del Sistema</p>
                            <p className="text-[10px] text-red-400/80 italic">¡PELIGRO! Borra TODA la información: transacciones, facturas, reglas y archivos de esta organización.</p>
                        </div>
                        <Button
                            variant="destructive"
                            onClick={handleFullReset}
                            disabled={saving}
                            className="bg-red-600 hover:bg-red-500 font-black uppercase tracking-tighter shadow-lg shadow-red-500/20"
                        >
                            {saving ? <Loader2 className="animate-spin mr-2 h-4 w-4" /> : <RotateCcw className="mr-2 h-4 w-4" />}
                            REINICIAR TODO
                        </Button>
                    </div>

                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                        <div className="flex flex-col items-start justify-between gap-4 p-4 bg-blue-500/5 rounded-xl border border-blue-500/20">
                            <div className="space-y-1">
                                <p className="text-white font-bold text-sm uppercase">Purgar Clientes</p>
                                <p className="text-[10px] text-blue-400/80">Elimina exclusivamente la base de datos de Clientes.</p>
                            </div>
                            <Button
                                variant="outline"
                                onClick={handleDeleteAllClients}
                                disabled={saving}
                                className="w-full border-blue-500/20 hover:bg-blue-500/10 text-blue-400 font-bold text-xs"
                            >
                                {saving ? <Loader2 className="animate-spin mr-2 h-3.5 w-3.5" /> : <Trash2 className="mr-2 h-3.5 w-3.5" />}
                                ELIMINAR CLIENTES
                            </Button>
                        </div>

                        <div className="flex flex-col items-start justify-between gap-4 p-4 bg-emerald-500/5 rounded-xl border border-emerald-500/20">
                            <div className="space-y-1">
                                <p className="text-white font-bold text-sm uppercase">Purgar Proveedores</p>
                                <p className="text-[10px] text-emerald-400/80">Elimina exclusivamente la base de datos de Proveedores.</p>
                            </div>
                            <Button
                                variant="outline"
                                onClick={handleDeleteAllSuppliers}
                                disabled={saving}
                                className="w-full border-emerald-500/20 hover:bg-emerald-500/10 text-emerald-400 font-bold text-xs"
                            >
                                {saving ? <Loader2 className="animate-spin mr-2 h-3.5 w-3.5" /> : <Trash2 className="mr-2 h-3.5 w-3.5" />}
                                ELIMINAR PROVEEDORES
                            </Button>
                        </div>
                    </div>
                </CardContent>
            </Card >

            <div className="fixed bottom-10 left-1/2 -translate-x-1/2 z-50">
                <Button onClick={handleSave} disabled={saving} size="lg" className={`h-14 px-8 text-lg font-black uppercase tracking-tighter shadow-2xl transition-all duration-500 ${success ? 'bg-emerald-500 ring-4 ring-emerald-500/20' : 'bg-emerald-600 hover:bg-emerald-500'}`}>
                    {saving ? <Loader2 className="animate-spin mr-2 h-6 w-6" /> : success ? <CheckCircle2 className="mr-2 h-6 w-6" /> : <Save className="mr-2 h-6 w-6" />}
                    {saving ? 'Guardando...' : success ? '¡GUARDADO!' : 'GUARDAR CONFIGURACIÓN'}
                </Button>
            </div>
        </div >
    )
}

'use client'

import { useState, useEffect } from 'react'
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogFooter } from '@/components/ui/dialog'
import { Button } from '@/components/ui/button'
import { Input } from '@/components/ui/input'
import { Label } from '@/components/ui/label'
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select'
import { Badge } from '@/components/ui/badge'
import { createClient } from '@/lib/supabase/client'
import { toast } from 'sonner'
import { Loader2, Calendar, Landmark, Hash, Search } from 'lucide-react'

interface InvoiceFormModalProps {
    isOpen: boolean
    onClose: () => void
    orgId: string
    type: 'factura_venta' | 'factura_compra' | 'ingreso_vario' | 'egreso_vario'
    invoice?: any // If editing
    onSuccess: () => void
}

export function InvoiceFormModal({ isOpen, onClose, orgId, type, invoice, onSuccess }: InvoiceFormModalProps) {
    const [loading, setLoading] = useState(false)
    const [entidades, setEntidades] = useState<any[]>([])
    const [searchingEntidad, setSearchingEntidad] = useState(false)
    const [formData, setFormData] = useState({
        entidad_id: '',
        tipo: type,
        numero: '',
        monto_total: 0,
        fecha_emision: new Date().toISOString().split('T')[0],
        fecha_vencimiento: new Date().toISOString().split('T')[0],
        condicion: 'cuenta_corriente',
        concepto: '',
        vinculado_id: 'none'
    })
    const [searchQuery, setSearchQuery] = useState('')
    const [originalInvoices, setOriginalInvoices] = useState<any[]>([])
    const [initialized, setInitialized] = useState(false)

    async function fetchInitialEntities() {
        setSearchingEntidad(true)
        const supabase = createClient()

        // Filtrado estricto por categoría
        const targetCat = type === 'factura_venta' ? 'cliente' : 'proveedor'

        const { data } = await supabase
            .from('entidades')
            .select('id, razon_social, cuit, categoria')
            .eq('organization_id', orgId)
            .in('categoria', [targetCat, 'ambos'])
            .order('razon_social')
            .limit(20)

        if (data) {
            let finalEntidades = [...data]
            // Si la entidad de la factura no está en los 20 primeros, la buscamos específicamente
            if (invoice?.entidad_id && !data.find(s => s.id === invoice.entidad_id)) {
                const { data: specificEntidad } = await supabase
                    .from('entidades')
                    .select('id, razon_social, cuit, categoria')
                    .eq('id', invoice.entidad_id)
                    .single()
                if (specificEntidad) finalEntidades = [specificEntidad, ...finalEntidades]
            }
            setEntidades(finalEntidades)
        }
        setSearchingEntidad(false)
    }

    useEffect(() => {
        if (isOpen && !initialized) {
            console.log('[InvoiceForm] Initializing form...')
            fetchInitialEntities()

            if (invoice) {
                setFormData({
                    entidad_id: invoice.entidad_id || '',
                    tipo: invoice.tipo || type,
                    numero: invoice.nro_factura || invoice.numero || '',
                    monto_total: Number(invoice.monto_total) || 0,
                    fecha_emision: invoice.fecha_emision || new Date().toISOString().split('T')[0],
                    fecha_vencimiento: invoice.fecha_vencimiento || new Date().toISOString().split('T')[0],
                    condicion: invoice.condicion || 'cuenta_corriente',
                    concepto: invoice.concepto || '',
                    vinculado_id: invoice.vinculado_id || 'none'
                })
                setSearchQuery(invoice.razon_social_entidad || invoice.razon_social_socio || '')
            } else {
                setFormData({
                    entidad_id: '',
                    tipo: type,
                    numero: '',
                    monto_total: 0,
                    fecha_emision: new Date().toISOString().split('T')[0],
                    fecha_vencimiento: new Date().toISOString().split('T')[0],
                    condicion: 'cuenta_corriente',
                    concepto: '',
                    vinculado_id: 'none'
                })
                setSearchQuery('')
            }
            setInitialized(true)
        }

        if (!isOpen) {
            setInitialized(false)
            setEntidades([])
            setSearchQuery('')
        }
    }, [invoice, isOpen, orgId, type, initialized])

    useEffect(() => {
        async function fetchOriginalInvoices() {
            if (!formData.entidad_id || !['nota_credito', 'nota_debito'].includes(formData.tipo)) return

            const supabase = createClient()
            const { data } = await supabase
                .from('comprobantes')
                .select('id, numero, fecha_emision, monto_total')
                .eq('entidad_id', formData.entidad_id)
                .in('tipo', ['factura_venta', 'factura_compra'])
                .order('fecha_emision', { ascending: false })

            if (data) setOriginalInvoices(data)
        }
        fetchOriginalInvoices()
    }, [formData.entidad_id, formData.tipo])

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault()
        console.log('[InvoiceForm] START handleSubmit', { formData, type })
        setLoading(true)

        try {
            if (!formData.entidad_id || formData.entidad_id === 'none') {
                toast.error(`Debe seleccionar un ${(type === 'factura_venta' || type === 'ingreso_vario') ? 'Cliente' : 'Proveedor'}`)
                setLoading(false)
                return
            }

            if (!formData.concepto || formData.concepto.trim() === '') {
                toast.error('El concepto es obligatorio')
                setLoading(false)
                return
            }

            const supabase = createClient()
            console.log('[InvoiceForm] Validating entidad:', formData.entidad_id)

            const { data: selectedEntidad, error: entidadError } = await supabase
                .from('entidades')
                .select('id, razon_social, cuit, categoria')
                .eq('id', formData.entidad_id)
                .single()

            if (entidadError || !selectedEntidad) {
                console.error('[InvoiceForm] Error entidad validation:', entidadError)
                toast.error('No se pudo validar la entidad seleccionada: ' + (entidadError?.message || 'No encontrada'))
                setLoading(false)
                return
            }

            if (!selectedEntidad) return

            console.log('[InvoiceForm] Entidad validada:', selectedEntidad.razon_social)

            const upsertData: Record<string, any> = {
                organization_id: orgId,
                entidad_id: formData.entidad_id,
                cuit_socio: selectedEntidad.cuit,
                razon_social_entidad: selectedEntidad.razon_social,
                nombre_entidad: selectedEntidad.razon_social,
                tipo: formData.tipo,
                nro_factura: formData.numero || null,
                monto_total: formData.monto_total,
                monto_pendiente: formData.condicion === 'contado' ? 0 : (invoice?.monto_pendiente ?? formData.monto_total),
                fecha_emision: formData.fecha_emision,
                fecha_vencimiento: formData.fecha_vencimiento,
                estado: formData.condicion === 'contado' ? 'pagado' : (invoice?.estado || 'pendiente'),
                condicion: formData.condicion,
                concepto: formData.concepto || null,
                moneda: 'ARS'
            }

            // Solo incluir id si estamos editando (evitar enviar undefined)
            if (invoice?.id) {
                upsertData.id = invoice.id
            }

            // Solo incluir vinculado_id para NC/ND (columna puede no existir en schemas antiguos)
            if (['nota_credito', 'nota_debito'].includes(formData.tipo)) {
                const vinculadoVal = formData.vinculado_id === 'none' ? null : (formData.vinculado_id || null)
                if (vinculadoVal) {
                    upsertData.vinculado_id = vinculadoVal
                }
            }

            console.log('[InvoiceForm] Sending to Supabase (Optimized with Timeout)...')
            const startTime = Date.now()

            let query;
            if (invoice?.id) {
                query = supabase.from('comprobantes').update(upsertData).eq('id', invoice.id).select().single()
            } else {
                query = supabase.from('comprobantes').insert([upsertData]).select().single()
            }

            // Timeout de 15 segundos
            const timeoutPromise = new Promise((_, reject) =>
                setTimeout(() => reject(new Error('Tiempo de espera agotado en la base de datos (15s)')), 15000)
            );

            const { data: savedInvoice, error } = (await Promise.race([
                query,
                timeoutPromise
            ])) as { data: any, error: any }

            console.log(`[InvoiceForm] DB Response in ${Date.now() - startTime}ms`, { error })

            if (error) {
                console.error('[InvoiceForm] Database error:', error)
                toast.error(`Error de base de datos: ${error.message}`)
                setLoading(false)
                return
            }

            // SI ES CONTADO -> GENERAR RECIBO AUTOMATICO
            if (formData.condicion === 'contado' && savedInvoice) {
                console.log('[InvoiceForm] Generando pago automático por Condición Contado...')

                // 1. Crear Movimiento de Tesorería
                const { data: mov, error: movErr } = await supabase.from('movimientos_tesoreria').insert({
                    organization_id: orgId,
                    entidad_id: formData.entidad_id,
                    tipo: (type === 'factura_venta' || type === 'ingreso_vario') ? 'cobro' : 'pago',
                    monto_total: formData.monto_total,
                    fecha: formData.fecha_emision,
                    observaciones: `Cierre automático: Pago Contado ${savedInvoice.numero || ''}`
                }).select().single()

                if (!movErr && mov) {
                    // 2. Crear Instrumento (Efectivo por defecto)
                    await supabase.from('instrumentos_pago').insert({
                        movimiento_id: mov.id,
                        metodo: 'efectivo',
                        monto: formData.monto_total,
                        fecha_disponibilidad: formData.fecha_emision
                    })

                    // 3. Crear Aplicación
                    await supabase.from('aplicaciones_pago').insert({
                        movimiento_id: mov.id,
                        comprobante_id: savedInvoice.id,
                        monto_aplicado: formData.monto_total
                    })

                    toast.success(`Pago automático ${mov.numero} registrado`)
                } else if (movErr) {
                    console.error('[InvoiceForm] Error en pago auto:', movErr)
                }
            }

            console.log('[InvoiceForm] SUCCESS - Closing Modal and Refreshing')
            toast.success(invoice ? 'Comprobante actualizado' : 'Comprobante registrado con éxito')

            // Acción inmediata: Cerrar modal
            onClose()

            // Acción diferida: Refrescar datos para no bloquear el cierre
            setTimeout(() => {
                onSuccess()
            }, 100)
        } catch (err: any) {
            console.error('[InvoiceForm] CRITICAL ERROR:', err)
            toast.error('Error crítico: ' + (err.message || 'Error desconocido'))
        } finally {
            console.log('[InvoiceForm] END handleSubmit')
            setLoading(false)
        }
    }

    return (
        <Dialog open={isOpen} onOpenChange={onClose}>
            <DialogContent className="bg-gray-950 border-gray-800 text-white sm:max-w-[500px] max-h-[90vh] flex flex-col p-0 overflow-hidden">
                <div className="p-6 pb-2">
                    <DialogHeader>
                        <DialogTitle className="text-xl font-bold flex items-center gap-2">
                            {invoice ? 'Editar Comprobante' : `Nuevo ${type === 'factura_venta' ? 'Ingreso' : 'Egreso'}`}
                        </DialogTitle>
                    </DialogHeader>
                </div>

                <div className="max-h-[70vh] overflow-y-auto pr-4 custom-scrollbar">
                    <form onSubmit={handleSubmit} className="space-y-4 py-4 focus:outline-none">
                        <div className="grid grid-cols-2 gap-4">
                            {/* 1. Tipo de Comprobante - Movido al principio para evitar overlap con la búsqueda */}
                            <div className="col-span-2 space-y-2">
                                <Label className="text-xs uppercase text-emerald-500 font-bold tracking-wider">¿Qué estás registrando?</Label>
                                <Select
                                    value={formData.tipo}
                                    onValueChange={(val: any) => {
                                        console.log('[Form] Tipo cambiado a:', val)
                                        setFormData({ ...formData, tipo: val })
                                    }}
                                >
                                    <SelectTrigger className="bg-gray-900 border-gray-800 h-11 focus:ring-emerald-500/50 z-[60]">
                                        <SelectValue placeholder="Seleccione el tipo..." />
                                    </SelectTrigger>
                                    <SelectContent className="bg-gray-950 border-gray-800 text-white z-[200]" position="popper" sideOffset={5}>
                                        <SelectItem value={type.includes('venta') || type.includes('ingreso') ? 'factura_venta' : 'factura_compra'} className="focus:bg-emerald-600 focus:text-white cursor-pointer">
                                            Factura (Original)
                                        </SelectItem>
                                        <SelectItem value={type.includes('venta') || type.includes('ingreso') ? 'ingreso_vario' : 'egreso_vario'} className="focus:bg-emerald-600 focus:text-white cursor-pointer">
                                            {type.includes('venta') || type.includes('ingreso') ? 'Ingresos Varios' : 'Egresos Varios'}
                                        </SelectItem>
                                        <SelectItem value="nota_credito" className="focus:bg-emerald-600 focus:text-white cursor-pointer">Nota de Crédito</SelectItem>
                                        <SelectItem value="nota_debito" className="focus:bg-emerald-600 focus:text-white cursor-pointer">Nota de Débito</SelectItem>
                                    </SelectContent>
                                </Select>
                            </div>

                            {/* Condición de Pago */}
                            <div className="col-span-2 space-y-2">
                                <Label className="text-xs uppercase text-gray-500 font-bold tracking-wider">Condición de Pago</Label>
                                <Select
                                    value={formData.condicion}
                                    onValueChange={(val: any) => setFormData({ ...formData, condicion: val })}
                                >
                                    <SelectTrigger className="bg-gray-900 border-gray-800 h-11 focus:ring-emerald-500/50">
                                        <SelectValue placeholder="Seleccione condición..." />
                                    </SelectTrigger>
                                    <SelectContent className="bg-gray-950 border-gray-800 text-white">
                                        <SelectItem value="cuenta_corriente">Cuenta Corriente (A cobrar luego)</SelectItem>
                                        <SelectItem value="contado">Contado (Pagado/Cobrado ahora)</SelectItem>
                                    </SelectContent>
                                </Select>
                            </div>

                            {/* Entidad (Cliente/Proveedor) */}
                            <div className="col-span-2 space-y-2">
                                <div className="flex justify-between items-center">
                                    <Label className="text-xs uppercase text-gray-500 font-bold">
                                        {type === 'factura_venta' ? 'Cliente / Entidad' : 'Proveedor / Entidad'}
                                    </Label>
                                    {formData.entidad_id && (
                                        <Badge variant="outline" className="text-[10px] bg-emerald-500/10 text-emerald-500 border-emerald-500/20">
                                            Entidad Seleccionada
                                        </Badge>
                                    )}
                                </div>
                                <div className="space-y-2 relative">
                                    <div className="flex items-center gap-2 bg-gray-900 border border-gray-800 rounded-lg px-3 focus-within:border-emerald-500/50 transition-colors">
                                        <Search className="w-4 h-4 text-gray-500" />
                                        <Input
                                            placeholder={`Buscar por nombre o CUIT...`}
                                            className="bg-transparent border-none focus-visible:ring-0 h-11 px-0"
                                            value={searchQuery}
                                            onChange={async (e) => {
                                                const term = e.target.value
                                                setSearchQuery(term)

                                                if (!term || term.length < 2) {
                                                    setEntidades([])
                                                    return
                                                }

                                                const supabase = createClient()
                                                const targetCat = (type === 'factura_venta' || type === 'ingreso_vario') ? 'cliente' : 'proveedor'

                                                setSearchingEntidad(true)
                                                const { data } = await supabase
                                                    .from('entidades')
                                                    .select('id, razon_social, cuit, categoria')
                                                    .eq('organization_id', orgId)
                                                    .in('categoria', [targetCat, 'ambos'])
                                                    .or(`razon_social.ilike.%${term}%,cuit.ilike.%${term}%`)
                                                    .limit(10)

                                                if (data) setEntidades(data)
                                                setSearchingEntidad(false)
                                            }}
                                        />
                                        {formData.entidad_id && (
                                            <button
                                                type="button"
                                                onClick={() => {
                                                    console.log('[InvoiceForm] Reseting entidad search...')
                                                    setFormData({ ...formData, entidad_id: '' })
                                                    setSearchQuery('')
                                                    fetchInitialEntities()
                                                }}
                                                className="text-[10px] bg-red-500/10 text-red-400 px-2 py-1 rounded hover:bg-red-500/20 font-bold uppercase transition-colors"
                                            >
                                                Cambiar
                                            </button>
                                        )}
                                    </div>

                                    {/* Lista de resultados - Añadido un z-index más agresivo and min-height behavior */}
                                    {entidades.length > 0 && (
                                        <div className="absolute top-full left-0 right-0 z-[200] mt-1 bg-gray-950 border border-emerald-500/30 rounded-lg shadow-[0_10px_40px_rgba(0,0,0,0.5)] overflow-hidden max-h-[180px] overflow-y-auto animate-in fade-in zoom-in-95 duration-200">
                                            <div className="p-1.5 bg-gray-900/50 border-b border-gray-800 text-[9px] uppercase font-bold text-gray-500 flex justify-between items-center">
                                                <span>Seleccione una entidad</span>
                                                <span className="text-emerald-500">{entidades.length} hallados</span>
                                            </div>
                                            {searchingEntidad ? (
                                                <div className="p-4 text-center text-xs text-gray-500 flex items-center justify-center gap-2">
                                                    <Loader2 className="w-3 h-3 animate-spin" />
                                                    Buscando...
                                                </div>
                                            ) : (
                                                entidades.map(s => (
                                                    <div
                                                        key={s.id}
                                                        onClick={() => {
                                                            console.log('[InvoiceForm] Entidad seleccionada:', s.razon_social)
                                                            setFormData({ ...formData, entidad_id: s.id })
                                                            setSearchQuery(s.razon_social)
                                                            setEntidades([])
                                                        }}
                                                        className={`p-3 cursor-pointer hover:bg-emerald-600/20 border-b border-gray-800/50 transition-all flex justify-between items-center ${formData.entidad_id === s.id ? 'bg-emerald-600/30 border-l-4 border-l-emerald-500 pl-2' : ''}`}
                                                    >
                                                        <div className="flex flex-col text-left">
                                                            <span className="text-sm font-bold text-white leading-none mb-1">{s.razon_social}</span>
                                                            <span className="text-[10px] text-gray-500 font-mono tracking-tight">{s.cuit}</span>
                                                        </div>
                                                        {formData.entidad_id === s.id && <div className="w-2 h-2 rounded-full bg-emerald-500 shadow-[0_0_10px_rgba(16,185,129,0.5)]" />}
                                                    </div>
                                                ))
                                            )}
                                        </div>
                                    )}
                                </div>
                            </div>

                            {/* Campo de Número de Comprobante */}
                            <div className="col-span-2 space-y-2">
                                <Label className="text-xs uppercase text-gray-500 font-bold">Número de Comprobante (Opcional)</Label>
                                <div className="relative">
                                    <Hash className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-500 pointer-events-none" />
                                    <Input
                                        placeholder="0001-00001234"
                                        value={formData.numero}
                                        onChange={(e) => setFormData({ ...formData, numero: e.target.value })}
                                        className="bg-gray-900 border-gray-800 pl-10 font-mono"
                                    />
                                </div>
                            </div>

                            {['nota_credito', 'nota_debito'].includes(formData.tipo) && (
                                <div className="col-span-2 space-y-2 animate-in fade-in slide-in-from-top-2">
                                    <Label className="text-xs uppercase text-amber-500 font-bold tracking-wider">Vincular a Comprobante Original (AFIP)</Label>
                                    <Select
                                        value={formData.vinculado_id}
                                        onValueChange={(val) => setFormData({ ...formData, vinculado_id: val })}
                                    >
                                        <SelectTrigger className="bg-gray-900 border-amber-500/20 h-11 text-xs">
                                            <SelectValue placeholder="Seleccione la factura que está ajustando..." />
                                        </SelectTrigger>
                                        <SelectContent className="bg-gray-900 border-gray-800 text-white max-h-[200px]">
                                            <SelectItem value="none">Sin vincular (ajuste suelto)</SelectItem>
                                            {originalInvoices.map(inv => (
                                                <SelectItem key={inv.id} value={inv.id}>
                                                    {inv.numero || 'S/N'} - {new Date(inv.fecha_emision).toLocaleDateString()} (${new Intl.NumberFormat('es-AR').format(inv.monto_total)})
                                                </SelectItem>
                                            ))}
                                        </SelectContent>
                                    </Select>
                                    <p className="text-[10px] text-gray-500 italic">Obligatorio segun RG 4540 de AFIP para notas de ajuste vinculadas.</p>
                                </div>
                            )}

                            <div className="col-span-2 space-y-2">
                                <Label className="text-xs uppercase text-gray-500 font-bold flex items-center gap-1">
                                    Concepto / Operación Personalizada
                                    <span className="text-red-500">*</span>
                                </Label>
                                <Input
                                    placeholder={type === 'factura_venta' ? 'Ej: Venta de servicios de consultoría' : 'Ej: Compra de insumos de oficina'}
                                    value={formData.concepto}
                                    onChange={(e) => setFormData({ ...formData, concepto: e.target.value })}
                                    className="bg-gray-900 border-gray-800"
                                />
                            </div>

                            <div className="space-y-2">
                                <Label className="text-xs uppercase text-gray-500 font-bold">Monto Total</Label>
                                <Input
                                    type="number"
                                    placeholder="0.00"
                                    value={formData.monto_total || ''}
                                    onChange={(e) => setFormData({ ...formData, monto_total: Number(e.target.value) })}
                                    className="bg-gray-900 border-gray-800 text-right font-bold h-11 text-emerald-400"
                                    required
                                />
                            </div>

                            <div className="space-y-2">
                                <Label className="text-xs uppercase text-gray-500 font-bold">Fecha Emisión</Label>
                                <div className="relative">
                                    <Calendar className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-500 pointer-events-none" />
                                    <Input
                                        type="date"
                                        value={formData.fecha_emision}
                                        onChange={(e) => {
                                            const newDate = e.target.value
                                            setFormData({
                                                ...formData,
                                                fecha_emision: newDate
                                            })
                                        }}
                                        className="bg-gray-900 border-gray-800 pl-10 block w-full h-11"
                                        required
                                    />
                                </div>
                            </div>

                            <div className="space-y-2">
                                <Label className="text-xs uppercase text-emerald-400 font-bold">Fecha Vencimiento</Label>
                                <div className="relative">
                                    <Calendar className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-emerald-500" />
                                    <Input
                                        type="date"
                                        value={formData.fecha_vencimiento}
                                        onChange={(e) => setFormData({ ...formData, fecha_vencimiento: e.target.value })}
                                        className="bg-gray-900 border-emerald-500/30 text-emerald-400 pl-10 h-11"
                                        required
                                    />
                                </div>
                            </div>
                        </div>

                        <DialogFooter className="pt-4 px-0">
                            <Button type="button" variant="ghost" onClick={onClose} disabled={loading} className="text-gray-400">
                                Cancelar
                            </Button>
                            <Button type="submit" className="bg-emerald-600 hover:bg-emerald-500 text-white font-bold text-sm" disabled={loading}>
                                {loading ? <Loader2 className="w-4 h-4 animate-spin mr-2" /> : null}
                                {invoice ? 'Guardar Cambios' : 'Registrar'}
                            </Button>
                        </DialogFooter>
                    </form>
                </div>
            </DialogContent>
        </Dialog>
    )
}

'use client'

import { useState, useEffect } from 'react'
import { createClient } from '@/lib/supabase/client'
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select'
import { Label } from '@/components/ui/label'
import { Loader2 } from 'lucide-react'

interface HierarchicalLocationSelectorProps {
    formData: {
        provincia: string
        departamento: string
        localidad: string
    }
    onChange: (updates: Partial<{ provincia: string, departamento: string, localidad: string }>) => void
}

export function HierarchicalLocationSelector({ formData, onChange }: HierarchicalLocationSelectorProps) {
    const [provinces, setProvinces] = useState<string[]>([])
    const [departments, setDepartments] = useState<string[]>([])
    const [localities, setLocalities] = useState<string[]>([])
    const [loading, setLoading] = useState({ p: false, d: false, l: false })

    const supabase = createClient()

    // Fetch provinces on mount
    useEffect(() => {
        const fetchProvinces = async () => {
            setLoading(prev => ({ ...prev, p: true }))
            const { data } = await supabase
                .from('geo_argentina')
                .select('provincia')

            if (data) {
                const unique = Array.from(new Set(data.map(d => d.provincia))).sort()
                setProvinces(unique)
            }
            setLoading(prev => ({ ...prev, p: false }))
        }
        fetchProvinces()
    }, [])

    // Fetch departments when province changes
    useEffect(() => {
        const prov = (formData.provincia || '').trim()
        if (!prov) {
            setDepartments([])
            return
        }

        const fetchDepartments = async () => {
            setLoading(prev => ({ ...prev, d: true }))
            const { data } = await supabase
                .from('geo_argentina')
                .select('departamento')
                .eq('provincia', prov)

            if (data) {
                const unique = Array.from(new Set(data.map(d => d.departamento))).sort()
                setDepartments(unique)
            }
            setLoading(prev => ({ ...prev, d: false }))
        }
        fetchDepartments()
    }, [formData.provincia])

    // Fetch localities when department changes
    useEffect(() => {
        const prov = (formData.provincia || '').trim()
        const dept = (formData.departamento || '').trim()

        if (!dept || !prov) {
            setLocalities([])
            return
        }

        const fetchLocalities = async () => {
            setLoading(prev => ({ ...prev, l: true }))
            const { data } = await supabase
                .from('geo_argentina')
                .select('localidad')
                .eq('provincia', prov)
                .eq('departamento', dept)

            if (data) {
                const unique = Array.from(new Set(data.map(d => d.localidad))).sort()
                setLocalities(unique)
            }
            setLoading(prev => ({ ...prev, l: false }))
        }
        fetchLocalities()
    }, [formData.departamento, formData.provincia])

    return (
        <div className="space-y-4">
            <div className="space-y-2">
                <Label className="text-xs text-gray-400">Provincia</Label>
                <Select
                    value={formData.provincia}
                    onValueChange={(v) => onChange({ provincia: v, departamento: '', localidad: '' })}
                >
                    <SelectTrigger className="bg-gray-900 border-gray-800">
                        {loading.p ? <Loader2 className="w-4 h-4 animate-spin" /> : <SelectValue placeholder="Seleccionar provincia" />}
                    </SelectTrigger>
                    <SelectContent className="bg-gray-900 border-gray-800 text-white max-h-60">
                        {provinces.map(p => (
                            <SelectItem key={p} value={p}>{p}</SelectItem>
                        ))}
                    </SelectContent>
                </Select>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <div className="space-y-2">
                    <Label className="text-xs text-gray-400">Departamento/Partido</Label>
                    <Select
                        value={formData.departamento}
                        onValueChange={(v) => onChange({ departamento: v, localidad: '' })}
                        disabled={!formData.provincia || loading.d}
                    >
                        <SelectTrigger className="bg-gray-900 border-gray-800">
                            {loading.d ? <Loader2 className="w-4 h-4 animate-spin" /> : <SelectValue placeholder="Seleccionar departamento" />}
                        </SelectTrigger>
                        <SelectContent className="bg-gray-900 border-gray-800 text-white max-h-60">
                            {departments.map(d => (
                                <SelectItem key={d} value={d}>{d}</SelectItem>
                            ))}
                        </SelectContent>
                    </Select>
                </div>

                <div className="space-y-2">
                    <Label className="text-xs text-gray-400">Localidad</Label>
                    <Select
                        value={formData.localidad}
                        onValueChange={(v) => onChange({ localidad: v })}
                        disabled={!formData.departamento || loading.l}
                    >
                        <SelectTrigger className="bg-gray-900 border-gray-800">
                            {loading.l ? <Loader2 className="w-4 h-4 animate-spin" /> : <SelectValue placeholder="Seleccionar localidad" />}
                        </SelectTrigger>
                        <SelectContent className="bg-gray-900 border-gray-800 text-white max-h-60">
                            {localities.map(l => (
                                <SelectItem key={l} value={l}>{l}</SelectItem>
                            ))}
                        </SelectContent>
                    </Select>
                </div>
            </div>
        </div>
    )
}

'use client'

import { useState, useEffect } from 'react'
import {
    Dialog,
    DialogContent,
    DialogHeader,
    DialogTitle,
} from '@/components/ui/dialog'
import { Button } from '@/components/ui/button'
import { Input } from '@/components/ui/input'
import { Label } from '@/components/ui/label'
import { Badge } from '@/components/ui/badge'
import { ScrollArea } from '@/components/ui/scroll-area'
import {
    CheckCircle2,
    ChevronRight,
    ChevronLeft,
    Plus,
    Trash2,
    Banknote,
    Calendar,
    Hash,
    Loader2,
    Briefcase,
    AlertTriangle
} from 'lucide-react'
import { createClient } from '@/lib/supabase/client'
import { toast } from 'sonner'

interface Check {
    id: string
    detalle_referencia: string
    banco: string
    monto: number
    fecha_disponibilidad: string
    cant_endosos: number
    tipo_cheque: 'comun' | 'cpd'
}

interface PaymentWizardProps {
    isOpen: boolean
    onClose: () => void
    orgId: string
    entidadId: string
    razonSocial: string
    tipo: 'cobro' | 'pago'
    onSuccess: () => void
}

export function PaymentWizard({ isOpen, onClose, orgId, entidadId, razonSocial, tipo, onSuccess }: PaymentWizardProps) {
    const [step, setStep] = useState(1)
    const [loading, setLoading] = useState(false)
    const [pendingInvoices, setPendingInvoices] = useState<any[]>([])
    const [selectedInvoices, setSelectedInvoices] = useState<string[]>([])
    const [instruments, setInstruments] = useState<any[]>([
        { id: '1', metodo: 'efectivo', monto: 0, fecha_disponibilidad: new Date().toISOString().split('T')[0] }
    ])
    const [numero, setNumero] = useState('')

    useEffect(() => {
        if (step === 2 && instruments.length === 1 && instruments[0].monto === 0) {
            updateInstrument('1', { monto: totalSelected })
        }
    }, [step])

    const [availableChecks, setAvailableChecks] = useState<Check[]>([])
    const [isSelectingCheck, setIsSelectingCheck] = useState(false)

    useEffect(() => {
        if (isOpen && entidadId) {
            fetchPendingInvoices()
            if (tipo === 'pago') fetchAvailableChecks()
        }
    }, [isOpen, entidadId])

    async function fetchAvailableChecks() {
        const supabase = createClient()
        const { data } = await supabase
            .from('instrumentos_pago')
            .select('id, detalle_referencia, banco, monto, fecha_disponibilidad, cant_endosos, tipo_cheque')
            .eq('metodo', 'cheque_terceros')
            .eq('estado', 'pendiente')

        if (data) setAvailableChecks(data)
    }

    async function fetchPendingInvoices() {
        const supabase = createClient()
        const targetTypes = tipo === 'cobro'
            ? ['factura_venta', 'nota_credito', 'nota_debito']
            : ['factura_compra', 'nota_credito', 'nota_debito']

        const { data } = await supabase
            .from('comprobantes')
            .select('*')
            .eq('organization_id', orgId)
            .eq('entidad_id', entidadId)
            .in('tipo', targetTypes)
            .neq('estado', 'pagado')
            .order('fecha_vencimiento', { ascending: true })

        if (data) setPendingInvoices(data)
    }

    const totalSelected = pendingInvoices
        .filter(inv => selectedInvoices.includes(inv.id))
        .reduce((acc, curr) => {
            if (curr.tipo === 'nota_credito') return acc - curr.monto_pendiente
            return acc + curr.monto_pendiente
        }, 0)

    const totalInstruments = instruments.reduce((acc, curr) => acc + (Number(curr.monto) || 0), 0)
    const difference = totalSelected - totalInstruments
    const isPartialPayment = totalInstruments > 0 && totalInstruments < totalSelected - 0.01
    const isOverPayment = totalInstruments > totalSelected + 0.01

    const handleAddInstrument = () => {
        setInstruments([...instruments, {
            id: Date.now().toString(),
            metodo: 'cheque_terceros',
            monto: difference > 0 ? difference : 0,
            fecha_disponibilidad: new Date().toISOString().split('T')[0]
        }])
    }

    const handleRemoveInstrument = (id: string) => {
        setInstruments(instruments.filter(i => i.id !== id))
    }

    const updateInstrument = (id: string, updates: any) => {
        setInstruments(instruments.map(i => i.id === id ? { ...i, ...updates } : i))
    }

    const handleConfirm = async () => {
        if (loading) return
        setLoading(true)
        const supabase = createClient()

        try {
            const { data: mov, error: movErr } = await supabase
                .from('movimientos_tesoreria')
                .insert({
                    organization_id: orgId,
                    entidad_id: entidadId,
                    tipo: tipo,
                    nro_comprobante: numero || null,
                    monto_total: totalInstruments,
                    fecha: new Date().toISOString().split('T')[0],
                    observaciones: `Generado desde el asistente de ${tipo}`
                })
                .select()
                .single()

            if (movErr) throw new Error(`Error al crear movimiento: ${movErr.message}`)

            const instrumentsPayload = instruments
                .filter(i => i.monto > 0)
                .map(i => ({
                    organization_id: orgId,
                    movimiento_id: mov.id,
                    metodo: i.metodo === 'endoso' ? 'cheque_terceros' : i.metodo,
                    monto: i.monto,
                    fecha_disponibilidad: i.fecha_disponibilidad,
                    banco: i.banco || null,
                    detalle_referencia: i.detalle_referencia || null,
                    vinculo_instrumento_id: i.vinculo_instrumento_id || null,
                    cant_endosos: i.metodo === 'endoso' ? (i.cant_endosos || 0) + 1 : 0,
                    tipo_cheque: i.tipo_cheque || 'cpd'
                }))

            if (instrumentsPayload.length > 0) {
                const { error: insErr } = await supabase.from('instrumentos_pago').insert(instrumentsPayload)
                if (insErr) throw new Error(`Error al crear instrumentos: ${insErr.message}`)

                const endosados = instruments.filter(i => i.metodo === 'endoso' && i.vinculo_instrumento_id)
                if (endosados.length > 0) {
                    for (const endoso of endosados) {
                        await supabase.from('instrumentos_pago')
                            .update({
                                estado: 'endosado',
                                cant_endosos: (endoso.cant_endosos || 0) + 1
                            })
                            .eq('id', endoso.vinculo_instrumento_id)
                    }
                }
            }

            const selectedComprobantes = selectedInvoices.map(id => pendingInvoices.find(i => i.id === id)).filter(Boolean)
            const facturas = selectedComprobantes.filter(inv => inv.tipo !== 'nota_credito')
            const notasCredito = selectedComprobantes.filter(inv => inv.tipo === 'nota_credito')

            for (const nc of notasCredito) {
                await supabase.from('aplicaciones_pago').insert({
                    movimiento_id: mov.id,
                    comprobante_id: nc.id,
                    monto_aplicado: nc.monto_pendiente
                })
                await supabase.from('comprobantes')
                    .update({ monto_pendiente: 0, estado: 'pagado' })
                    .eq('id', nc.id)
            }

            let remainingPayment = totalInstruments
            for (const inv of facturas) {
                if (remainingPayment <= 0.01) break
                const amountToApply = Math.min(remainingPayment, inv.monto_pendiente)
                await supabase.from('aplicaciones_pago').insert({
                    movimiento_id: mov.id,
                    comprobante_id: inv.id,
                    monto_aplicado: amountToApply
                })
                const newMontoPendiente = Math.max(0, inv.monto_pendiente - amountToApply)
                await supabase.from('comprobantes')
                    .update({
                        monto_pendiente: newMontoPendiente,
                        estado: newMontoPendiente <= 0.01 ? 'pagado' : 'parcial'
                    })
                    .eq('id', inv.id)
                remainingPayment -= amountToApply
            }

            toast.success(`${tipo === 'cobro' ? 'Recibo' : 'Orden de Pago'} ${mov.numero || ''} generado con éxito`)
            onSuccess()
            onClose()
        } catch (err: any) {
            console.error('[PaymentWizard] Error:', err)
            toast.error('Error al procesar: ' + (err.message || 'Error desconocido'))
        } finally {
            setLoading(false)
        }
    }

    return (
        <Dialog open={isOpen} onOpenChange={onClose}>
            <DialogContent className="max-w-4xl bg-gray-950 border-gray-800 text-white min-h-[600px] flex flex-col p-0 overflow-hidden">
                <div className="p-6 border-b border-gray-800 bg-emerald-500/5">
                    <div className="flex items-center justify-between">
                        <div className="flex-1">
                            <DialogTitle className="text-2xl font-bold flex items-center gap-3">
                                {tipo === 'cobro' ? 'Nuevo Recibo' : 'Nueva Orden de Pago'}
                                <Badge className="bg-emerald-600 text-white font-bold border-none px-3 py-1">
                                    Fase {step} de 2
                                </Badge>
                            </DialogTitle>
                            <div className="flex items-center gap-4 mt-2">
                                <p className="text-sm text-gray-500 font-medium">{razonSocial}</p>
                                <div className="h-4 w-px bg-gray-800" />
                                <div className="flex items-center gap-2">
                                    <Label className="text-[10px] uppercase text-gray-400 font-bold whitespace-nowrap">Nro (Opcional)</Label>
                                    <Input
                                        placeholder={tipo === 'cobro' ? 'Ej: R-001' : 'Ej: OP-001'}
                                        value={numero}
                                        onChange={(e) => setNumero(e.target.value)}
                                        className="h-8 w-36 bg-gray-950 border-gray-800 text-xs font-mono py-1 focus:ring-emerald-500/20 focus:border-emerald-500/50"
                                    />
                                </div>
                            </div>
                        </div>
                    </div>
                </div>

                <div className="flex-1 overflow-y-auto p-6">
                    {step === 1 ? (
                        <div className="space-y-6">
                            <div className="flex items-center justify-between mb-2">
                                <Label className="text-lg font-bold">Seleccionar Comprobantes Pendientes</Label>
                            </div>
                            <ScrollArea className="max-h-[400px] pr-4">
                                <div className="space-y-3">
                                    {pendingInvoices.length === 0 ? (
                                        <div className="p-12 text-center border-2 border-dashed border-gray-800 rounded-2xl text-gray-500">
                                            No hay comprobantes pendientes.
                                        </div>
                                    ) : (
                                        <div className="grid gap-3">
                                            {pendingInvoices.map(inv => (
                                                <div
                                                    key={inv.id}
                                                    onClick={() => {
                                                        if (selectedInvoices.includes(inv.id)) {
                                                            setSelectedInvoices(prev => prev.filter(id => id !== inv.id))
                                                        } else {
                                                            setSelectedInvoices(prev => [...prev, inv.id])
                                                        }
                                                    }}
                                                    className={`p-4 rounded-2xl border-2 transition-all cursor-pointer ${selectedInvoices.includes(inv.id) ? 'bg-emerald-500/10 border-emerald-500/40' : 'bg-gray-900 border-gray-800'}`}
                                                >
                                                    <div className="flex justify-between items-center">
                                                        <div className="flex gap-4 items-center">
                                                            <div className={`w-8 h-8 rounded-full flex items-center justify-center ${selectedInvoices.includes(inv.id) ? 'bg-emerald-500' : 'bg-gray-800'}`}>
                                                                {selectedInvoices.includes(inv.id) && <CheckCircle2 className="w-5 h-5 text-white" />}
                                                            </div>
                                                            <div>
                                                                <p className="font-bold">{inv.numero || 'S/N'}</p>
                                                                <p className="text-xs text-gray-500">{new Date(inv.fecha_vencimiento).toLocaleDateString()}</p>
                                                            </div>
                                                        </div>
                                                        <p className="font-mono font-bold text-emerald-400">
                                                            ${new Intl.NumberFormat('es-AR').format(inv.monto_pendiente)}
                                                        </p>
                                                    </div>
                                                </div>
                                            ))}
                                        </div>
                                    )}
                                </div>
                            </ScrollArea>
                        </div>
                    ) : (
                        <div className="space-y-6">
                            <div className="flex justify-between items-center">
                                <Label className="text-lg font-bold">Carga de Instrumentos</Label>
                                <Button size="sm" onClick={handleAddInstrument} variant="outline" className="text-emerald-400">
                                    <Plus className="w-4 h-4 mr-2" /> Agregar Valor
                                </Button>
                            </div>

                            <ScrollArea className="max-h-[400px] pr-4">
                                <div className="space-y-4">
                                    {instruments.map((ins) => (
                                        <div key={ins.id} className="p-5 bg-gray-900 border border-gray-800 rounded-2xl relative">
                                            {instruments.length > 1 && (
                                                <button onClick={() => handleRemoveInstrument(ins.id)} className="absolute top-4 right-4 text-gray-600 hover:text-red-500">
                                                    <Trash2 className="w-4 h-4" />
                                                </button>
                                            )}
                                            <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
                                                <div className="space-y-2">
                                                    <Label className="text-[10px] uppercase text-gray-500 font-bold">Medio</Label>
                                                    <select
                                                        value={ins.metodo}
                                                        onChange={(e) => updateInstrument(ins.id, { metodo: e.target.value, vinculo_instrumento_id: null })}
                                                        className="w-full bg-gray-950 border border-gray-800 rounded-lg p-2 text-xs text-white"
                                                    >
                                                        <option value="efectivo">Efectivo</option>
                                                        <option value="transferencia">Transferencia</option>
                                                        <option value="cheque_terceros">Cheque (Terceros)</option>
                                                        <option value="cheque_propio">Cheque (Propio)</option>
                                                        {tipo === 'pago' && <option value="endoso">Endoso de Terceros</option>}
                                                    </select>
                                                </div>

                                                {ins.metodo === 'endoso' ? (
                                                    <div className="col-span-3 flex items-end gap-2">
                                                        <Button
                                                            variant="outline"
                                                            className={`w-full border-dashed h-9 text-xs ${ins.limitExceeded ? 'border-red-500 bg-red-500/10' : 'border-gray-700'}`}
                                                            onClick={() => setIsSelectingCheck(true)}
                                                        >
                                                            {ins.vinculo_instrumento_id ? `Cheque ${ins.detalle_referencia} (${ins.cant_endosos} endosos)` : 'Seleccionar cheque de cartera...'}
                                                        </Button>
                                                        {ins.limitExceeded && (
                                                            <div className="flex items-center gap-1 text-red-400 text-[10px] animate-pulse">
                                                                <AlertTriangle className="w-3 h-3" /> LÍMITE BCRA
                                                            </div>
                                                        )}
                                                    </div>
                                                ) : (
                                                    <>
                                                        <div className="space-y-2">
                                                            <Label className="text-[10px] uppercase text-gray-500 font-bold">Monto</Label>
                                                            <Input
                                                                type="number"
                                                                value={ins.monto}
                                                                onChange={(e) => updateInstrument(ins.id, { monto: Number(e.target.value) })}
                                                                className="bg-gray-950 border-gray-800 text-emerald-400 h-9"
                                                            />
                                                        </div>
                                                        <div className="space-y-2">
                                                            <Label className="text-[10px] uppercase text-gray-500 font-bold">Vencimiento</Label>
                                                            <Input
                                                                type="date"
                                                                value={ins.fecha_disponibilidad}
                                                                onChange={(e) => updateInstrument(ins.id, { fecha_disponibilidad: e.target.value })}
                                                                className="bg-gray-950 border-gray-800 h-9 text-xs"
                                                            />
                                                        </div>
                                                        <div className="space-y-2">
                                                            <Label className="text-[10px] uppercase text-gray-500 font-bold">Ref / Tipo</Label>
                                                            <div className="flex gap-1">
                                                                <Input
                                                                    placeholder="Nro"
                                                                    value={ins.detalle_referencia || ''}
                                                                    onChange={(e) => updateInstrument(ins.id, { detalle_referencia: e.target.value })}
                                                                    className="bg-gray-950 border-gray-800 h-9 text-xs w-2/3"
                                                                />
                                                                <select
                                                                    value={ins.tipo_cheque || 'cpd'}
                                                                    onChange={(e) => updateInstrument(ins.id, { tipo_cheque: e.target.value })}
                                                                    className="bg-gray-950 border border-gray-800 rounded-lg text-[9px] w-1/3 text-white"
                                                                >
                                                                    <option value="cpd">CPD</option>
                                                                    <option value="comun">Común</option>
                                                                </select>
                                                            </div>
                                                        </div>
                                                    </>
                                                )}
                                            </div>
                                        </div>
                                    ))}
                                </div>
                            </ScrollArea>

                            {isSelectingCheck && (
                                <div className="fixed inset-0 z-[100] flex items-center justify-center bg-black/60 backdrop-blur-sm p-4">
                                    <div className="bg-gray-950 border border-gray-800 w-full max-w-lg rounded-2xl p-6">
                                        <h3 className="text-lg font-bold mb-4 flex items-center gap-2">
                                            <Briefcase className="w-5 h-5 text-emerald-400" /> Seleccionar Cheque a Endosar
                                        </h3>
                                        <ScrollArea className="h-64 pr-4">
                                            <div className="space-y-2">
                                                {availableChecks.length === 0 ? (
                                                    <p className="text-center py-8 text-gray-500 text-sm italic">No hay cheques en cartera.</p>
                                                ) : availableChecks.map(c => {
                                                    const limit = c.tipo_cheque === 'comun' ? 1 : 2;
                                                    const isLimitReached = c.cant_endosos >= limit;

                                                    return (
                                                        <div
                                                            key={c.id}
                                                            onClick={() => {
                                                                const targetIns = instruments.find(i => i.metodo === 'endoso' && !i.vinculo_instrumento_id) || instruments.find(i => i.metodo === 'endoso');
                                                                if (targetIns) {
                                                                    updateInstrument(targetIns.id, {
                                                                        vinculo_instrumento_id: c.id,
                                                                        monto: c.monto,
                                                                        detalle_referencia: c.detalle_referencia,
                                                                        banco: c.banco,
                                                                        fecha_disponibilidad: c.fecha_disponibilidad,
                                                                        cant_endosos: c.cant_endosos,
                                                                        tipo_cheque: c.tipo_cheque,
                                                                        limitExceeded: isLimitReached
                                                                    });
                                                                }
                                                                setIsSelectingCheck(false);
                                                            }}
                                                            className={`p-3 border rounded-xl cursor-pointer transition-all flex justify-between items-center ${isLimitReached ? 'bg-red-500/5 border-red-500/20 hover:border-red-500/50' : 'bg-gray-900 border-gray-800 hover:border-emerald-500/50'}`}
                                                        >
                                                            <div>
                                                                <div className="flex items-center gap-2">
                                                                    <p className="font-bold text-xs">{c.detalle_referencia} - {c.banco}</p>
                                                                    <Badge variant="outline" className="text-[8px] py-0 h-3">{c.tipo_cheque || 'cpd'}</Badge>
                                                                </div>
                                                                <p className={`text-[10px] ${isLimitReached ? 'text-red-400 font-bold' : 'text-gray-500'}`}>
                                                                    Endosos: {c.cant_endosos || 0} / {limit} {isLimitReached && '(LÍMITE ALCANZADO)'}
                                                                </p>
                                                            </div>
                                                            <p className="font-mono font-bold text-emerald-400">${new Intl.NumberFormat('es-AR').format(c.monto)}</p>
                                                        </div>
                                                    );
                                                })}
                                            </div>
                                        </ScrollArea>
                                        <div className="mt-6 flex justify-end">
                                            <Button variant="ghost" onClick={() => setIsSelectingCheck(false)}>Cerrar</Button>
                                        </div>
                                    </div>
                                </div>
                            )}
                        </div>
                    )}
                </div>

                <div className="p-6 border-t border-gray-800 bg-gray-900/50 flex items-center justify-between">
                    <div className="flex flex-col">
                        <span className="text-[10px] text-gray-400 uppercase font-bold tracking-widest">Total Valores</span>
                        <p className="text-lg font-bold text-emerald-400">
                            ${new Intl.NumberFormat('es-AR').format(totalInstruments)}
                        </p>
                    </div>

                    <div className="flex items-center gap-3">
                        <Button variant="ghost" onClick={onClose} disabled={loading} className="text-gray-500 hover:text-white">Cancelar</Button>
                        {step === 2 && <Button variant="outline" onClick={() => setStep(1)} disabled={loading} className="border-gray-800 text-gray-400"><ChevronLeft className="w-4 h-4 mr-2" /> Atrás</Button>}
                        {step === 1 ? (
                            <Button onClick={() => setStep(2)} disabled={selectedInvoices.length === 0} className="bg-emerald-600 hover:bg-emerald-500 text-white font-bold text-sm">Siguiente <ChevronRight className="w-4 h-4 ml-2" /></Button>
                        ) : (
                            <Button
                                onClick={handleConfirm}
                                disabled={totalInstruments === 0 || loading || isOverPayment || instruments.some(i => i.limitExceeded)}
                                className="bg-emerald-600 hover:bg-emerald-500 text-white font-bold px-8 shadow-lg shadow-emerald-900/20 text-sm"
                            >
                                {loading ? <Loader2 className="w-4 h-4 animate-spin mr-2" /> : <CheckCircle2 className="w-4 h-4 mr-2" />} Finalizar Y Confirmar
                            </Button>
                        )}
                    </div>
                </div>
            </DialogContent>
        </Dialog>
    )
}

'use client'

import { useRef, useState, useEffect } from 'react'
import { createClient } from '@/lib/supabase/client'
import { Card } from '@/components/ui/card'
import { Badge } from '@/components/ui/badge'
import { Users, ShieldCheck, Landmark, Search, Plus, Edit2, Trash2, FileDown, Upload, FileSpreadsheet, Loader2 } from 'lucide-react'
import { Input } from '@/components/ui/input'
import { Button } from '@/components/ui/button'
import { EntityModal } from './entity-modal'
import { toast } from 'sonner'
import { downloadEntityTemplate, exportEntitiesToExcel, parseEntityExcel } from '@/lib/excel-utils'
import { ImportPreviewModal } from './import-preview-modal'

interface SuppliersTabProps {
    orgId: string
    category?: 'cliente' | 'proveedor' | 'ambos'
}

export function SuppliersTab({ orgId, category = 'proveedor' }: SuppliersTabProps) {
    const [suppliers, setSuppliers] = useState<any[]>([])
    const [loading, setLoading] = useState(true)
    const [searchTerm, setSearchTerm] = useState('')
    const [isEntityModalOpen, setIsEntityModalOpen] = useState(false)
    const [selectedEntity, setSelectedEntity] = useState<any>(null)
    const [currentPage, setCurrentPage] = useState(1)
    const [itemsPerPage, setItemsPerPage] = useState(100)
    const [importData, setImportData] = useState<any[]>([])
    const [isImportPreviewOpen, setIsImportPreviewOpen] = useState(false)
    const [currentFileName, setCurrentFileName] = useState<string>('')
    const fileInputRef = useRef<HTMLInputElement>(null)
    const supabase = createClient()

    const fetchEntities = async () => {
        setLoading(true)
        // Fetch entities (entidades) and their trusted CBUs
        let query = supabase
            .from('entidades')
            .select('*')
            .eq('organization_id', orgId)

        if (category !== 'ambos') {
            query = query.eq('categoria', category)
        }

        const { data: entitiesData } = await query.order('razon_social', { ascending: true })

        const { data: trustData } = await supabase
            .from('trust_ledger')
            .select('cuit, cbu, is_trusted')
            .eq('organization_id', orgId)

        if (entitiesData) {
            const combined = entitiesData.map(ent => ({
                ...ent,
                trusted_cbus: trustData?.filter(t => t.cuit === ent.cuit) || []
            }))
            setSuppliers(combined)
        }
        setLoading(false)
    }

    useEffect(() => {
        fetchEntities()
    }, [orgId, category])

    const filteredSuppliers = suppliers.filter(s =>
        s.razon_social.toLowerCase().includes(searchTerm.toLowerCase()) ||
        s.cuit.includes(searchTerm)
    )

    const totalPages = Math.ceil(filteredSuppliers.length / itemsPerPage)
    const paginatedSuppliers = filteredSuppliers.slice(
        (currentPage - 1) * itemsPerPage,
        currentPage * itemsPerPage
    )

    const handleDelete = async (id: string, name: string, currentCategory: string) => {
        const actionLabel = category === 'cliente' ? 'cliente' : 'proveedor'
        const otherCategory = category === 'cliente' ? 'proveedor' : 'cliente'

        if (!confirm(`¿Estás seguro de que deseas eliminar a "${name}" como ${actionLabel}? Esta acción no se puede deshacer.`)) {
            return
        }

        try {
            if (currentCategory === 'ambos') {
                // Downgrade category instead of deleting
                console.log(`[Delete] Downgrading entity ${id} from 'ambos' to '${otherCategory}'`)
                const { error } = await supabase
                    .from('entidades')
                    .update({ categoria: otherCategory })
                    .eq('id', id)

                if (error) throw error
                toast.success(`Ahora "${name}" ya no es ${actionLabel}, pero sigue guardado como ${otherCategory}`)
            } else {
                // Physical delete
                console.log(`[Delete] Physical delete for entity ${id}`)
                const { error } = await supabase
                    .from('entidades')
                    .delete()
                    .eq('id', id)

                if (error) throw error
                toast.success(`${name} eliminado con éxito`)
            }

            fetchEntities()
        } catch (err: any) {
            console.error('Error deleting entity:', err)
            toast.error('Error al eliminar: ' + err.message)
        }
    }

    const handleDownloadTemplate = () => {
        downloadEntityTemplate(category)
        toast.success('Plantilla descargada')
    }

    const handleImportExcel = async (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0]
        if (!file) return

        console.log('[Import] Starting parse for file:', file.name)
        setCurrentFileName(file.name)
        const loadingToast = toast.loading('Procesando archivo Excel...')

        try {
            const { data: parsedData, errors: parserErrors } = await parseEntityExcel(file)
            console.log('[Import] Parsed records:', parsedData.length)

            // NEW: Handle specific parser errors (e.g., empty file, missing headers)
            if (parserErrors && parserErrors.length > 0) {
                toast.error(parserErrors[0])
                return
            }

            if (parsedData.length === 0) {
                toast.error('No se encontraron datos en el archivo. Verificá que la hoja no esté vacía.')
                return
            }

            // Dictionary of common geographical aliases to avoid false positives
            const GEO_ALIASES: Record<string, { localidad?: string, provincia?: string, departamento?: string }> = {
                'caba': { localidad: 'ciudad autónoma de buenos aires', provincia: 'ciudad autónoma de buenos aires', departamento: 'comuna 1' },
                'mza': { provincia: 'mendoza' },
                'mendoza': { provincia: 'mendoza' },
                'cba': { provincia: 'córdoba' },
                'cordoba': { provincia: 'córdoba' },
                'sta fe': { provincia: 'santa fe' },
                'santa fe': { provincia: 'santa fe' },
                'bsas': { provincia: 'buenos aires' },
                'buenos aires': { provincia: 'buenos aires' },
                'tuc': { provincia: 'tucumán' },
                'sl': { provincia: 'san luis' },
                'sj': { provincia: 'san juan' },
                'er': { provincia: 'entre ríos' },
                'rn': { provincia: 'río negro' },
                'chubut': { provincia: 'chubut' },
                'lpa': { provincia: 'la pampa' },
                'mis': { provincia: 'misiones' },
                'corr': { provincia: 'corrientes' },
                'sgo': { provincia: 'santiago del estero' },
                'tdf': { provincia: 'tierra del fuego' }
            }

            const resolveAlias = (val: string, type: 'provincia' | 'localidad' | 'departamento') => {
                const clean = val.trim().toLowerCase()
                const match = GEO_ALIASES[clean]
                if (match) return match[type] || clean
                return clean
            }

            // NEW: Proactive Batch Check for Locations
            console.log('[Import] Step 2: Proactive Location Validation...')
            const uniqueLocs = Array.from(new Set(
                parsedData
                    .filter((ent: any) => ent.localidad && ent.provincia)
                    .map((ent: any) => {
                        const p = resolveAlias(ent.provincia, 'provincia')
                        const l = resolveAlias(ent.localidad, 'localidad')
                        return `${l}|${p}`
                    })
            ))

            const validLocMap = new Map<string, any>()
            if (uniqueLocs.length > 0) {
                const { data: geoData } = await supabase
                    .from('geo_argentina')
                    .select('localidad, provincia, departamento')

                geoData?.forEach((g: any) => {
                    validLocMap.set(`${g.localidad.trim().toLowerCase()}|${g.provincia.trim().toLowerCase()}`, g)
                })
            }
            const dataWithContext = parsedData.map((ent: any) => {
                const errors: string[] = []

                // 1. Critical Information Validation
                if (!ent.razon_social?.trim()) {
                    errors.push('Falta Razón Social')
                }

                const cleanCuit = (ent.cuit || '').toString().replace(/[^\d]/g, '')
                if (!cleanCuit) {
                    errors.push('Falta CUIT')
                } else if (cleanCuit.length !== 11) {
                    errors.push('CUIT incompleto (necesita 11 dígitos)')
                }

                // 2. Location SILENT Normalization & Strict Error Mapping
                let normalizedProv = resolveAlias(ent.provincia || '', 'provincia')
                let normalizedLoc = resolveAlias(ent.localidad || '', 'localidad')
                const locKey = `${normalizedLoc}|${normalizedProv}`
                const geoMatch = validLocMap.get(locKey)

                // If we found a match, update the entity data with official names
                if (geoMatch) {
                    ent.provincia = geoMatch.provincia
                    ent.localidad = geoMatch.localidad
                    ent.departamento = geoMatch.departamento
                } else if (!ent.localidad || !ent.provincia) {
                    // MISSING location is now an Error, not a warning
                    errors.push('Falta información de ubicación')
                } else {
                    // If it's not a match but it has some data, we DON'T add a warning/error anymore.
                    // We trust it enough to be imported if the user doesn't care about geo-tagging,
                    // or we simply avoid the noise.
                    console.log(`[Import] Location not in DB but not blocking: ${locKey}`)
                }

                return {
                    ...ent,
                    errors,
                    warnings: [], // Explicitly empty to avoid UI noise
                    isValid: errors.length === 0
                }
            })

            setImportData(dataWithContext)
            setIsImportPreviewOpen(true)
            console.log('[Import] Preview modal opened with validation.')
        } catch (err: any) {
            console.error('[Import] FATAL ERROR:', err)
            toast.error('Error crítico en el procesador: ' + (err.message || 'Desconocido'))
        } finally {
            toast.dismiss(loadingToast)
            if (e.target) e.target.value = '' // Reset input
        }
    }

    const onRowUpdate = (updatedRow: any) => {
        setImportData(prev => prev.map(row =>
            row.id === updatedRow.id ? updatedRow : row
        ))
    }

    const onConfirmImport = async (validData: any[]) => {
        console.log('[ConfirmImport] Starting optimized persist for', validData.length, 'records')
        const loadingToast = toast.loading(`Normalizando y guardando ${validData.length} registros...`)

        try {
            if (!orgId) throw new Error('No se detectó el ID de la organización')

            // 1. BATCH NORMALIZATION
            console.log('[ConfirmImport] Step 1: Batch Normalizing Locations...')
            const uniqueLocations = Array.from(new Set(
                validData
                    .filter(ent => !ent.geo_lat && ent.localidad && ent.provincia)
                    .map(ent => `${ent.localidad.trim().toLowerCase()}|${ent.provincia.trim().toLowerCase()}`)
            ))

            const geoCachedMap = new Map<string, any>()

            if (uniqueLocations.length > 0) {
                console.log(`[ConfirmImport] Fetching ${uniqueLocations.length} unique locations from DB...`)

                // We fetch all potential matches in one go using OR filters or filtering by the list of provinces
                // For simplicity and speed, we fetch only columns we need
                const { data: geoData } = await supabase
                    .from('geo_argentina')
                    .select('localidad, departamento, provincia, latitud, longitud')

                // Build a quick lookup map
                geoData?.forEach(g => {
                    const key = `${g.localidad.trim().toLowerCase()}|${g.provincia.trim().toLowerCase()}`
                    if (!geoCachedMap.has(key)) {
                        geoCachedMap.set(key, g)
                    }
                })
            }

            // 1.5 FETCH EXISTING CATEGORIES TO PREVENT OVERWRITES
            console.log('[ConfirmImport] Step 1.5: Checking for existing categories...')
            const allCuits = validData.map((ent: any) => ent.cuit)
            const { data: existingEnts } = await supabase
                .from('entidades')
                .select('cuit, categoria')
                .eq('organization_id', orgId)
                .in('cuit', allCuits)

            const existingCategoryMap = new Map<string, string>()
            existingEnts?.forEach((e: any) => {
                existingCategoryMap.set(e.cuit, e.categoria)
            })

            // 2. MAPPING & CHUNKING
            console.log('[ConfirmImport] Step 2: Preparing data chunks...')
            const normalizedData = validData.map(ent => {
                const key = `${(ent.localidad || '').trim().toLowerCase()}|${(ent.provincia || '').trim().toLowerCase()}`
                const geoMatch = geoCachedMap.get(key)

                // Intelligent Category Merging
                const currentCategory = category === 'ambos' ? 'proveedor' : category
                const existingCategory = existingCategoryMap.get(ent.cuit)

                let finalCategory: 'cliente' | 'proveedor' | 'ambos' = currentCategory
                if (existingCategory && existingCategory !== 'ambos' && existingCategory !== currentCategory) {
                    finalCategory = 'ambos'
                } else if (existingCategory === 'ambos') {
                    finalCategory = 'ambos'
                }

                return {
                    organization_id: orgId,
                    cuit: ent.cuit,
                    razon_social: ent.razon_social,
                    categoria: finalCategory as any,
                    metadata: {
                        cbu_habitual: ent.cbu_habitual,
                        direccion: ent.direccion,
                        localidad: geoMatch?.localidad || ent.localidad,
                        departamento: geoMatch?.departamento || ent.departamento,
                        provincia: geoMatch?.provincia || ent.provincia,
                        codigo_postal: ent.codigo_postal,
                        email: ent.email,
                        telefono_1: ent.telefono_1,
                        contacto: ent.contacto,
                        geo_lat: geoMatch?.latitud || ent.geo_lat,
                        geo_lon: geoMatch?.longitud || ent.geo_lon
                    },
                    updated_at: new Date().toISOString()
                }
            })

            // 3. CHUNKED UPSERT (Batches of 50)
            const CHUNK_SIZE = 50
            for (let i = 0; i < normalizedData.length; i += CHUNK_SIZE) {
                const chunk = normalizedData.slice(i, i + CHUNK_SIZE)
                console.log(`[ConfirmImport] Upserting chunk ${i / CHUNK_SIZE + 1}...`)

                const { error: upsertError } = await supabase
                    .from('entidades')
                    .upsert(chunk, { onConflict: 'organization_id, cuit' })

                if (upsertError) {
                    console.error('[ConfirmImport] Error in chunk upsert:', upsertError)
                    throw new Error(`Error en lote ${i / CHUNK_SIZE + 1}: ${upsertError.message}`)
                }
            }

            // Log explicitly to import history via API to bypass RLS
            try {
                await fetch('/api/imports/log', {
                    method: 'POST',
                    headers: { 'Content-Type': 'application/json' },
                    body: JSON.stringify({
                        organization_id: orgId,
                        nombre_archivo: currentFileName || `importacion_${category}.xlsx`,
                        metadata: {
                            context: category,
                            processed: validData.length,
                            inserted: validData.length
                        }
                    })
                })
            } catch (historyErr) {
                console.error('[ConfirmImport] Failed to log import history:', historyErr)
            }

            console.log('[ConfirmImport] SUCCESS. Process finished.')
            toast.success(`${validData.length} registros importados correctamente`)
            fetchEntities()
        } catch (err: any) {
            console.error('[ConfirmImport] FATAL ERROR:', err)
            toast.error('Error al guardar datos: ' + (err.message || 'Error desconocido'))
            throw err
        } finally {
            toast.dismiss(loadingToast)
        }
    }


    const handleExportExcel = () => {
        exportEntitiesToExcel(suppliers, category)
        toast.success('Datos exportados')
    }

    return (
        <div className="space-y-6">
            {/* INPUT OCULTO PARA IMPORTACIÓN */}
            <input
                type="file"
                ref={fileInputRef}
                className="hidden"
                accept=".xlsx, .xls, .csv"
                onChange={handleImportExcel}
            />

            {/* CABECERA: CONTADOR Y BOTÓN NUEVO */}
            <div className="flex items-center justify-between border-b border-gray-800 pb-4">
                <div className="flex items-center gap-3">
                    <div className="p-2 bg-emerald-500/10 rounded-lg">
                        <Users className="h-5 w-5 text-emerald-500" />
                    </div>
                    <div>
                        <h2 className="text-lg font-bold text-white leading-none">
                            {category === 'cliente' ? 'Clientes' : 'Proveedores'} Registrados
                        </h2>
                        <span className="text-xs text-gray-500 font-medium">{suppliers.length} registros en total</span>
                    </div>
                </div>

                <Button
                    onClick={() => {
                        setSelectedEntity(null)
                        setIsEntityModalOpen(true)
                    }}
                    className="bg-emerald-600 hover:bg-emerald-500 text-white font-bold h-9"
                >
                    <Plus className="w-4 h-4 mr-2" />
                    Nuevo {category === 'cliente' ? 'Cliente' : 'Proveedor'}
                </Button>
            </div>

            {/* ACCIONES DE DATOS: Títulos y Botones 1, 2, 3 */}
            <div className="flex flex-col md:flex-row items-center gap-3 bg-gray-900/50 p-4 rounded-xl border border-gray-800">
                <div className="flex flex-wrap items-center gap-3">
                    <Button
                        variant="secondary"
                        size="sm"
                        onClick={handleDownloadTemplate}
                        className="bg-gray-800 hover:bg-gray-700 text-gray-200 border-gray-700 h-9"
                    >
                        <FileDown className="w-4 h-4 mr-2 text-emerald-500" />
                        B1: Descargar Plantilla
                    </Button>
                    <Button
                        variant="secondary"
                        size="sm"
                        onClick={() => fileInputRef.current?.click()}
                        className="bg-gray-800 hover:bg-gray-700 text-gray-200 border-gray-700 h-9"
                    >
                        <Upload className="w-4 h-4 mr-2 text-blue-500" />
                        B2: Importar {category === 'cliente' ? 'Clientes' : 'Proveedores'}
                    </Button>
                    <Button
                        variant="secondary"
                        size="sm"
                        onClick={handleExportExcel}
                        className="bg-gray-800 hover:bg-gray-700 text-gray-200 border-gray-700 h-9"
                    >
                        <FileSpreadsheet className="w-4 h-4 mr-2 text-amber-500" />
                        B3: Exportar {category === 'cliente' ? 'Clientes' : 'Proveedores'}
                    </Button>
                </div>

                <div className="relative flex-1 w-full md:min-w-[300px]">
                    <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 h-4 w-4 text-gray-500" />
                    <Input
                        placeholder={`Buscar ${category === 'cliente' ? 'cliente' : 'proveedor'}...`}
                        className="pl-10 bg-gray-900 border-gray-800 text-white h-9 w-full"
                        value={searchTerm}
                        onChange={(e) => setSearchTerm(e.target.value)}
                    />
                </div>
            </div>

            <div className="border border-gray-800 rounded-xl overflow-hidden bg-gray-900/50">
                <div className="max-h-[600px] overflow-y-auto overflow-x-auto scrollbar-thin scrollbar-thumb-emerald-500/20 hover:scrollbar-thumb-emerald-500/40 scrollbar-track-transparent">
                    <table className="w-full text-left text-xs border-separate border-spacing-0">
                        <thead className="bg-gray-800 text-[11px] font-bold text-gray-400 sticky top-0 z-10">
                            <tr>
                                <th className="px-6 py-4 sticky top-0 z-20 bg-gray-800">Razón Social / CUIT</th>
                                <th className="px-6 py-4 sticky top-0 z-20 bg-gray-800">Categoría</th>
                                <th className="px-6 py-4 sticky top-0 z-20 bg-gray-800">CBU / CVU Principales</th>
                                <th className="px-6 py-4 text-center sticky top-0 z-20 bg-gray-800">Acciones</th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-gray-800">
                            {loading ? (
                                <tr>
                                    <td colSpan={4} className="p-12 text-center text-gray-500 italic">Cargando directorio...</td>
                                </tr>
                            ) : paginatedSuppliers.length === 0 ? (
                                <tr>
                                    <td colSpan={4} className="p-12 text-center">
                                        <div className="flex flex-col items-center gap-2">
                                            <Users className="w-12 h-12 text-gray-700" />
                                            <h3 className="text-sm font-semibold text-white">No se encontraron {category === 'cliente' ? 'clientes' : 'proveedores'}</h3>
                                            <p className="text-xs text-gray-500">Agrega una nueva entidad manualmente para comenzar.</p>
                                        </div>
                                    </td>
                                </tr>
                            ) : (
                                paginatedSuppliers.map(supplier => (
                                    <tr key={supplier.id} className="hover:bg-white/5 transition-colors group">
                                        <td className="px-6 py-3">
                                            <div className="flex flex-col">
                                                <span className="font-bold text-white text-sm">{supplier.razon_social}</span>
                                                <span className="text-[10px] text-gray-500 font-mono">CUIT: {supplier.cuit}</span>
                                            </div>
                                        </td>
                                        <td className="px-6 py-3">
                                            <Badge className={`text-[9px] font-bold uppercase ${supplier.categoria === 'cliente' ? 'bg-blue-500/10 text-blue-400 border-blue-500/20' : 'bg-emerald-500/10 text-emerald-500 border-emerald-500/20'}`}>
                                                {supplier.categoria}
                                            </Badge>
                                        </td>
                                        <td className="px-6 py-3">
                                            <div className="flex flex-col gap-1">
                                                {supplier.trusted_cbus.slice(0, 2).map((t: any) => (
                                                    <div key={t.cbu} className="flex items-center gap-2">
                                                        <Landmark className="h-3 w-3 text-gray-600" />
                                                        <code className="text-[10px] text-gray-300 font-mono">{t.cbu}</code>
                                                        <ShieldCheck className="h-3 w-3 text-emerald-500" />
                                                    </div>
                                                ))}
                                                {supplier.trusted_cbus.length === 0 && (
                                                    <span className="text-[10px] text-gray-600 italic">Sin CBU validado</span>
                                                )}
                                                {supplier.trusted_cbus.length > 2 && (
                                                    <span className="text-[9px] text-emerald-500 font-bold">+{supplier.trusted_cbus.length - 2} más</span>
                                                )}
                                            </div>
                                        </td>
                                        <td className="px-6 py-3">
                                            <div className="flex justify-center gap-1">
                                                <Button
                                                    variant="ghost"
                                                    size="icon"
                                                    className="h-8 w-8 text-gray-500 hover:text-white hover:bg-white/10"
                                                    onClick={() => {
                                                        setSelectedEntity(supplier)
                                                        setIsEntityModalOpen(true)
                                                    }}
                                                >
                                                    <Edit2 className="w-3.5 h-3.5" />
                                                </Button>
                                                <Button
                                                    variant="ghost"
                                                    size="icon"
                                                    className="h-8 w-8 text-gray-500 hover:text-red-400 hover:bg-red-400/10"
                                                    onClick={() => handleDelete(supplier.id, supplier.razon_social, supplier.categoria)}
                                                >
                                                    <Trash2 className="w-3.5 h-3.5" />
                                                </Button>
                                            </div>
                                        </td>
                                    </tr>
                                ))
                            )}
                        </tbody>
                    </table>
                </div>

                {/* Paginación */}
                <div className="p-4 border-t border-gray-800 bg-gray-900/40 flex flex-col md:flex-row justify-between items-center gap-4">
                    <div className="text-[11px] text-gray-500 font-medium flex items-center gap-4">
                        <span>
                            Mostrando <span className="text-gray-300">{(currentPage - 1) * itemsPerPage + 1}</span> - <span className="text-gray-300">{Math.min(currentPage * itemsPerPage, filteredSuppliers.length)}</span> de <span className="text-gray-300">{filteredSuppliers.length}</span> entidades
                        </span>

                        <div className="flex items-center gap-2 border-l border-gray-800 pl-4">
                            <span className="text-gray-600">Ver:</span>
                            {[20, 25, 50, 100, 200].map(size => (
                                <button
                                    key={size}
                                    onClick={() => {
                                        setItemsPerPage(size)
                                        setCurrentPage(1)
                                    }}
                                    className={`px-2 py-0.5 rounded text-[10px] font-bold transition-all ${itemsPerPage === size ? 'bg-emerald-500/20 text-emerald-400 border border-emerald-500/30' : 'text-gray-600 hover:text-gray-400'}`}
                                >
                                    {size}
                                </button>
                            ))}
                        </div>
                    </div>

                    {totalPages > 1 && (
                        <div className="flex items-center gap-2">
                            <Button
                                variant="outline"
                                size="sm"
                                onClick={() => setCurrentPage(prev => Math.max(1, prev - 1))}
                                disabled={currentPage === 1}
                                className="h-8 px-3 border-gray-800 bg-gray-900 hover:bg-gray-800 text-gray-300 text-[10px] font-bold uppercase transition-all"
                            >
                                Anterior
                            </Button>
                            <div className="flex items-center gap-1 px-3">
                                <span className="text-[10px] font-bold text-emerald-500">{currentPage}</span>
                                <span className="text-[10px] font-bold text-gray-600">/</span>
                                <span className="text-[10px] font-bold text-gray-400">{totalPages}</span>
                            </div>
                            <Button
                                variant="outline"
                                size="sm"
                                onClick={() => setCurrentPage(prev => Math.min(totalPages, prev + 1))}
                                disabled={currentPage === totalPages}
                                className="h-8 px-3 border-gray-800 bg-gray-900 hover:bg-gray-800 text-gray-300 text-[10px] font-bold uppercase transition-all"
                            >
                                Siguiente
                            </Button>
                        </div>
                    )}
                </div>
            </div>
            <EntityModal
                isOpen={isEntityModalOpen}
                onClose={() => setIsEntityModalOpen(false)}
                orgId={orgId}
                entity={selectedEntity}
                onSuccess={fetchEntities}
                defaultCategory={category === 'ambos' ? 'proveedor' : category as 'cliente' | 'proveedor'}
            />
            <ImportPreviewModal
                isOpen={isImportPreviewOpen}
                onClose={() => setIsImportPreviewOpen(false)}
                data={importData}
                category={category}
                onConfirm={onConfirmImport}
                onRowUpdate={onRowUpdate}
            />
        </div>
    )
}

'use client'

import { useState, useEffect, useRef, Fragment } from 'react'
import { createClient } from '@/lib/supabase/client'
import { Card } from '@/components/ui/card'
// Table components removed to use native HTML tables for better sticky performance
import {
    FileText,
    ChevronDown,
    ChevronUp,
    Trash2,
    Download,
    Clock,
    Search,
    RefreshCcw,
    Upload,
    DownloadCloud,
    Tag,
    Plus,
    Info,
    Printer
} from 'lucide-react'
import { Badge } from '@/components/ui/badge'
import { Button } from '@/components/ui/button'
import { Input } from '@/components/ui/input'
import { toast } from 'sonner'
import { exportTreasuryMovementToExcel, downloadTreasuryTemplate } from '@/lib/excel-utils'
import { exportTreasuryMovementToPDF } from '@/lib/pdf-utils'
import { TreasuryManualEntry } from './treasury-manual-entry'

interface TreasuryHistoryProps {
    orgId: string
    accountId?: string
    typeFilter?: 'cobro' | 'pago'
    claseDocumentoFilter?: string[]
}

export function TreasuryHistory({ orgId, accountId, typeFilter, claseDocumentoFilter }: TreasuryHistoryProps) {
    const [movements, setMovements] = useState<any[]>([])
    const [loading, setLoading] = useState(true)
    const [expandedMov, setExpandedMov] = useState<string | null>(null)
    const [searchTerm, setSearchTerm] = useState('')
    const [isUploading, setIsUploading] = useState(false)
    const [selectedIds, setSelectedIds] = useState<Set<string>>(new Set())
    const [isDeletingBulk, setIsDeletingBulk] = useState(false)
    const [isManualEntryOpen, setIsManualEntryOpen] = useState(false)
    const [currentPage, setCurrentPage] = useState(1)
    const [itemsPerPage, setItemsPerPage] = useState(100)
    const fileInputRef = useRef<HTMLInputElement>(null)
    const supabase = createClient()

    async function fetchMovements() {
        setLoading(true)
        let query = supabase
            .from('movimientos_tesoreria')
            .select(`
                *,
                entidades (razon_social),
                instrumentos_pago (*),
                transacciones (id),
                aplicaciones_pago (
                    monto_aplicado,
                    comprobante_id,
                    comprobantes (*)
                )
            `)
            .eq('organization_id', orgId)
            .order('fecha', { ascending: false })
            .order('created_at', { ascending: false })

        if (typeFilter) {
            query = query.eq('tipo', typeFilter)
        }

        if (accountId && accountId !== 'all') {
            query = query.eq('cuenta_id', accountId)
        }

        if (claseDocumentoFilter && claseDocumentoFilter.length > 0) {
            query = query.in('clase_documento', claseDocumentoFilter)
        }

        const { data, error } = await query

        if (error) {
            console.error('Error fetching movements:', error)
            toast.error('Error al cargar el historial')
        } else {
            setMovements(data || [])
        }
        setLoading(false)
    }

    useEffect(() => {
        fetchMovements()
    }, [orgId, typeFilter, accountId])

    const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0]
        if (!file) return

        setIsUploading(true)
        const formData = new FormData()
        formData.append('file', file)
        formData.append('context', typeFilter === 'cobro' ? 'receipt' : 'payment')

        try {
            const response = await fetch('/api/upload', {
                method: 'POST',
                body: formData,
            })

            const result = await response.json()

            if (response.ok) {
                toast.success(`Importación exitosa: ${result.count} movimientos cargados.`)
                fetchMovements()
            } else {
                toast.error(`Error en importación: ${result.error || 'Desconocido'}`)
            }
        } catch (error) {
            console.error('Error uploading treasury movements:', error)
            toast.error('Error de red al intentar importar.')
        } finally {
            setIsUploading(false)
            if (fileInputRef.current) fileInputRef.current.value = ''
        }
    }

    const filteredMovements = movements.filter(m =>
        m.entidades?.razon_social?.toLowerCase().includes(searchTerm.toLowerCase()) ||
        (m.nro_comprobante || '').toLowerCase().includes(searchTerm.toLowerCase()) ||
        m.observaciones?.toLowerCase().includes(searchTerm.toLowerCase())
    )

    // Paginación
    const totalPages = Math.ceil(filteredMovements.length / itemsPerPage)
    const paginatedMovements = filteredMovements.slice(
        (currentPage - 1) * itemsPerPage,
        currentPage * itemsPerPage
    )

    const toggleSelect = (id: string) => {
        const next = new Set(selectedIds)
        if (next.has(id)) next.delete(id)
        else next.add(id)
        setSelectedIds(next)
    }

    const toggleSelectAll = () => {
        if (selectedIds.size === filteredMovements.length && filteredMovements.length > 0) {
            setSelectedIds(new Set())
        } else {
            setSelectedIds(new Set(filteredMovements.map(m => m.id)))
        }
    }

    const deleteMovementLogic = async (movId: string) => {
        const mov = movements.find(m => m.id === movId)
        if (!mov) return

        if (mov.aplicaciones_pago && mov.aplicaciones_pago.length > 0) {
            for (const app of mov.aplicaciones_pago) {
                const { data: inv } = await supabase.from('comprobantes')
                    .select('monto_pendiente, monto_total, tipo')
                    .eq('id', app.comprobante_id)
                    .single()

                if (inv) {
                    const restoredMonto = inv.tipo === 'nota_credito'
                        ? Number(app.monto_aplicado)
                        : Number(inv.monto_pendiente) + Number(app.monto_aplicado)

                    const newEstado = restoredMonto >= inv.monto_total ? 'pendiente' : (restoredMonto <= 0.05 ? 'pagado' : 'parcial')

                    await supabase.from('comprobantes')
                        .update({ monto_pendiente: restoredMonto, estado: newEstado })
                        .eq('id', app.comprobante_id)
                }
            }
        }

        await supabase.from('aplicaciones_pago').delete().eq('movimiento_id', movId)
        await supabase.from('instrumentos_pago').delete().eq('movimiento_id', movId)
        await supabase.from('movimientos_tesoreria').delete().eq('id', movId)
    }

    const handleDelete = async (movId: string) => {
        if (!confirm('¿Estás seguro? Se restaurarán los saldos de facturas.')) return
        setLoading(true)
        try {
            await deleteMovementLogic(movId)
            toast.success('Movimiento eliminado')
            fetchMovements()
        } catch (err: any) {
            toast.error('Error: ' + err.message)
        } finally {
            setLoading(false)
        }
    }

    const handleBulkDelete = async () => {
        if (!confirm(`¿Borrar ${selectedIds.size} seleccionados?`)) return
        setIsDeletingBulk(true)
        setLoading(true)
        for (const id of Array.from(selectedIds)) {
            await deleteMovementLogic(id)
        }
        setSelectedIds(new Set())
        toast.success(`Eliminados correctamente`)
        fetchMovements()
        setIsDeletingBulk(false)
        setLoading(false)
    }

    const title = typeFilter === 'cobro' ? 'Recibos' : 'Órdenes de Pago'
    const subtitle = typeFilter === 'cobro' ? 'Gestión de cobranzas a clientes.' : 'Gestión de pagos a proveedores.'

    return (
        <Card className="p-6 bg-gray-950 border-gray-800 text-white min-h-[500px]">
            <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-6 gap-4">
                <div>
                    <h2 className="text-xl font-bold flex items-center gap-2">
                        <Clock className="w-5 h-5 text-emerald-400" />
                        {title}
                    </h2>
                    <p className="text-sm text-gray-500">{subtitle}</p>
                </div>
                <div className="flex gap-2 w-full md:w-auto">
                    <Button
                        variant={selectedIds.size > 0 ? "destructive" : "outline"}
                        size="sm"
                        className={`gap-2 h-9 ${selectedIds.size > 0 ? '' : 'opacity-40 border-gray-700'}`}
                        onClick={handleBulkDelete}
                        disabled={isDeletingBulk || selectedIds.size === 0}
                    >
                        <Trash2 className="w-4 h-4" />
                        {isDeletingBulk ? '...' : (selectedIds.size > 0 ? `Borrar ${selectedIds.size}` : 'Borrar')}
                    </Button>

                    <input type="file" ref={fileInputRef} className="hidden" accept=".xlsx,.xls,.csv" onChange={handleFileUpload} />

                    <Button variant="outline" size="sm" className="bg-gray-900 text-gray-300 gap-2 h-9" onClick={() => downloadTreasuryTemplate(typeFilter === 'cobro' ? 'cobro' : 'pago')}>
                        <DownloadCloud className="w-4 h-4" />
                        <span className="hidden sm:inline">Plantilla</span>
                    </Button>

                    <Button variant="outline" size="sm" className="border-emerald-500/30 text-emerald-400 gap-2 h-9" onClick={() => fileInputRef.current?.click()} disabled={isUploading}>
                        <Upload className="w-4 h-4" />
                        <span className="hidden sm:inline">Importar</span>
                    </Button>

                    <Button size="sm" className="bg-emerald-600 hover:bg-emerald-500 text-white gap-2 h-9 font-bold px-4 text-sm" onClick={() => setIsManualEntryOpen(true)}>
                        <Plus className="w-4 h-4" />
                        <span className="hidden sm:inline">{typeFilter === 'cobro' ? 'Emitir Recibo' : 'Emitir Orden De Pago'}</span>
                    </Button>

                    <div className="relative flex-1 md:w-64">
                        <Search className="absolute left-3 top-2.5 w-4 h-4 text-gray-500" />
                        <Input placeholder="Buscar..." className="bg-gray-900 border-gray-800 pl-9 text-xs h-9" value={searchTerm} onChange={(e) => setSearchTerm(e.target.value)} />
                    </div>
                </div>
            </div>


            <div className="border border-gray-800 rounded-xl overflow-hidden bg-gray-900/50">
                <div className="max-h-[500px] overflow-y-auto overflow-x-auto scrollbar-thin scrollbar-thumb-emerald-500/20 hover:scrollbar-thumb-emerald-500/40 scrollbar-track-transparent">
                    <table className="w-full text-left text-xs border-separate border-spacing-0">
                        <thead className="bg-gray-800 sticky top-0 z-10">
                            <tr className="border-gray-800 hover:bg-transparent">
                                <th className="px-6 py-4 w-[40px] sticky top-0 z-20 bg-gray-800"><input type="checkbox" checked={selectedIds.size === filteredMovements.length && filteredMovements.length > 0} onChange={toggleSelectAll} /></th>
                                <th className="px-6 py-4 text-gray-500 text-[11px] font-bold text-center w-[30px] sticky top-0 z-20 bg-gray-800">C</th>
                                <th className="px-6 py-4 text-gray-500 text-[11px] font-bold sticky top-0 z-20 bg-gray-800">Fecha</th>
                                <th className="px-6 py-4 text-gray-500 text-[11px] font-bold sticky top-0 z-20 bg-gray-800">Comprobante</th>
                                <th className="px-6 py-4 text-gray-500 text-[11px] font-bold sticky top-0 z-20 bg-gray-800">Entidad</th>
                                <th className="px-6 py-4 text-gray-500 text-[11px] font-bold cursor-help sticky top-0 z-20 bg-gray-800" title="Si es blanco indica que el movimiento está imputado, si es verde que no lo está">
                                    <div className="flex items-center gap-1">
                                        Concepto
                                        <Info className="w-3.5 h-3.5 text-emerald-500/50" />
                                    </div>
                                </th>
                                <th className="px-6 py-4 text-gray-500 text-[11px] font-bold text-right sticky top-0 z-20 bg-gray-800">Total</th>
                                <th className="px-6 py-4 text-gray-500 text-[11px] font-bold text-center sticky top-0 z-20 bg-gray-800">Acciones</th>
                                <th className="px-6 py-4 w-[30px] sticky top-0 z-20 bg-gray-800"></th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-gray-800">
                            {loading ? (
                                <tr className="border-gray-800"><td colSpan={9} className="h-32 text-center text-gray-500">Cargando...</td></tr>
                            ) : paginatedMovements.map(mov => {
                                const isConciliated = mov.transacciones && mov.transacciones.length > 0;
                                const isExpanded = expandedMov === mov.id;

                                return (
                                    <Fragment key={mov.id}>
                                        <tr
                                            key={mov.id}
                                            className={`border-gray-800 transition-colors cursor-pointer ${isExpanded ? 'bg-emerald-500/5' : 'hover:bg-gray-800/30'}`}
                                            onClick={() => setExpandedMov(isExpanded ? null : mov.id)}
                                        >
                                            <td className="px-6 py-4" onClick={(e) => e.stopPropagation()}>
                                                <input type="checkbox" checked={selectedIds.has(mov.id)} onChange={() => toggleSelect(mov.id)} />
                                            </td>
                                            <td className="px-6 py-4 text-center">
                                                <div className={`
                                                    w-5 h-5 rounded-full flex items-center justify-center text-[10px] font-black
                                                    ${isConciliated ? 'bg-emerald-500/20 text-emerald-400 border border-emerald-500/30' : 'bg-gray-800/50 text-gray-600 border border-gray-800'}
                                                `}>
                                                    C
                                                </div>
                                            </td>
                                            <td className="px-6 py-4 font-mono text-xs">{new Date(mov.fecha).toLocaleDateString('es-AR')}</td>
                                            <td className="px-6 py-4"><Badge className="text-[9px] uppercase">{mov.nro_comprobante || mov.nro_factura || 'S/N'}</Badge></td>
                                            <td className="px-6 py-4 font-bold text-gray-200 text-xs">{mov.entidades?.razon_social}</td>
                                            <td className="px-6 py-4">
                                                <div className="flex flex-col gap-1 min-h-[1.2rem] justify-center">
                                                    {mov.aplicaciones_pago && mov.aplicaciones_pago.length > 0 ? (
                                                        <div className="flex flex-wrap gap-1">
                                                            {mov.aplicaciones_pago.map((app: any, idx: number) => (
                                                                <span
                                                                    key={idx}
                                                                    className="text-[10px] font-bold text-white uppercase tracking-tight bg-gray-800 px-1.5 py-0.5 rounded"
                                                                >
                                                                    {app.comprobantes?.nro_factura || app.comprobantes?.numero}
                                                                </span>
                                                            ))}
                                                        </div>
                                                    ) : (
                                                        <div className="flex flex-col">
                                                            <span className="text-xs font-bold text-emerald-400 uppercase tracking-tight">
                                                                {mov.concepto || 'Sin concepto'}
                                                            </span>
                                                            {mov.observaciones && mov.observaciones !== mov.concepto && (
                                                                <span className="text-[10px] text-gray-500 italic truncate max-w-[200px]">
                                                                    {mov.observaciones}
                                                                </span>
                                                            )}
                                                        </div>
                                                    )}
                                                </div>
                                            </td>
                                            <td className="px-6 py-4 text-right font-mono font-bold text-white text-xs">
                                                {new Intl.NumberFormat('es-AR', { style: 'currency', currency: 'ARS' }).format(mov.monto_total)}
                                            </td>
                                            <td className="px-6 py-4" onClick={(e) => e.stopPropagation()}>
                                                <div className="flex justify-center gap-1">
                                                    <Button variant="ghost" size="icon" className="h-8 w-8 text-emerald-400" onClick={() => setExpandedMov(isExpanded ? null : mov.id)} title="Ver Detalles"><FileText className="w-4 h-4" /></Button>
                                                    <Button variant="ghost" size="icon" className="h-8 w-8 text-red-400" onClick={() => exportTreasuryMovementToPDF(mov)} title="Descargar PDF"><Printer className="w-4 h-4" /></Button>
                                                    <Button variant="ghost" size="icon" className="h-8 w-8 text-blue-400" onClick={() => exportTreasuryMovementToExcel(mov)} title="Descargar EXCEL"><Download className="w-4 h-4" /></Button>
                                                    <Button variant="ghost" size="icon" className="h-8 w-8 text-red-500" onClick={() => handleDelete(mov.id)} title="Eliminar"><Trash2 className="w-3.5 h-3.5" /></Button>
                                                </div>
                                            </td>
                                            <td className="px-6 py-4">
                                                {isExpanded ? <ChevronUp className="w-4 h-4 text-emerald-500" /> : <ChevronDown className="w-4 h-4 text-gray-600" />}
                                            </td>
                                        </tr>

                                        {isExpanded && (
                                            <tr className="bg-gray-950/80 border-gray-800/50 hover:bg-transparent">
                                                <td colSpan={9} className="p-0">
                                                    <div className="p-6 border-l-2 border-emerald-500 bg-gray-900/40 animate-in slide-in-from-top-2 duration-200">
                                                        <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                                                            {/* Detalles de Instrumentos */}
                                                            <div>
                                                                <h4 className="text-[10px] font-black text-emerald-500 uppercase tracking-widest mb-4 flex items-center gap-2">
                                                                    <Tag className="w-3 h-3" /> Medios de Cobro / Pago
                                                                </h4>
                                                                <div className="space-y-2">
                                                                    {mov.instrumentos_pago && mov.instrumentos_pago.length > 0 ? (
                                                                        mov.instrumentos_pago.map((inst: any, idx: number) => (
                                                                            <div key={idx} className="flex justify-between items-center p-2.5 bg-gray-950/50 rounded-lg border border-gray-800">
                                                                                <div className="flex flex-col">
                                                                                    <span className="text-xs font-bold text-gray-200 uppercase">{inst.metodo}</span>
                                                                                    {inst.banco && <span className="text-[10px] text-gray-500 uppercase">{inst.banco} {(inst.detalle_referencia || inst.numero_cheque) ? `#${inst.detalle_referencia || inst.numero_cheque}` : ''}</span>}
                                                                                </div>
                                                                                <span className="font-mono text-sm font-bold text-white">
                                                                                    {new Intl.NumberFormat('es-AR', { style: 'currency', currency: 'ARS' }).format(inst.monto)}
                                                                                </span>
                                                                            </div>
                                                                        ))
                                                                    ) : (
                                                                        <div className="text-xs text-gray-600 italic">No hay instrumentos detallados</div>
                                                                    )}
                                                                </div>
                                                            </div>

                                                            {/* Detalles de Aplicaciones (Facturas) */}
                                                            <div>
                                                                <h4 className="text-[10px] font-black text-blue-500 uppercase tracking-widest mb-4 flex items-center gap-2">
                                                                    <FileText className="w-3 h-3" /> Facturas Imputadas
                                                                </h4>
                                                                <div className="space-y-2">
                                                                    {mov.aplicaciones_pago && mov.aplicaciones_pago.length > 0 ? (
                                                                        mov.aplicaciones_pago.map((app: any, idx: number) => (
                                                                            <div key={idx} className="flex justify-between items-center p-2.5 bg-gray-950/50 rounded-lg border border-gray-800">
                                                                                <div className="flex flex-col">
                                                                                    <span className="text-xs font-medium text-gray-300 uppercase">{app.comprobantes?.nro_factura}</span>
                                                                                    <span className="text-[9px] text-gray-500 uppercase">{app.comprobantes?.tipo}</span>
                                                                                </div>
                                                                                <span className="font-mono text-xs font-bold text-emerald-400">
                                                                                    {new Intl.NumberFormat('es-AR', { style: 'currency', currency: 'ARS' }).format(app.monto_aplicado)}
                                                                                </span>
                                                                            </div>
                                                                        ))
                                                                    ) : (
                                                                        <div className="text-xs text-gray-600 italic">Movimiento sin aplicaciones directas (Gasto/Concepto libre)</div>
                                                                    )}
                                                                </div>
                                                            </div>
                                                        </div>

                                                        {mov.observaciones && (
                                                            <div className="mt-6 p-3 bg-blue-500/5 rounded-lg border border-blue-500/10">
                                                                <p className="text-[10px] font-black text-blue-400 uppercase tracking-widest mb-1">Notas Administrativas</p>
                                                                <p className="text-xs text-gray-400">{mov.observaciones}</p>
                                                            </div>
                                                        )}
                                                    </div>
                                                </td>
                                            </tr>
                                        )}
                                    </Fragment>
                                );
                            })}
                        </tbody>
                    </table>
                </div>
            </div>

            {/* Paginación */}
            <div className="mt-4 p-4 border-t border-gray-800 bg-gray-900/40 flex flex-col md:flex-row justify-between items-center gap-4 rounded-xl">
                <div className="text-[11px] text-gray-500 font-medium flex items-center gap-4">
                    <span>
                        Mostrando <span className="text-gray-300">{(currentPage - 1) * itemsPerPage + 1}</span> - <span className="text-gray-300">{Math.min(currentPage * itemsPerPage, filteredMovements.length)}</span> de <span className="text-gray-300">{filteredMovements.length}</span> registros
                    </span>

                    <div className="flex items-center gap-2 border-l border-gray-800 pl-4">
                        <span className="text-gray-600">Ver:</span>
                        {[20, 25, 50, 100, 200].map(size => (
                            <button
                                key={size}
                                onClick={() => {
                                    setItemsPerPage(size)
                                    setCurrentPage(1)
                                }}
                                className={`px-2 py-0.5 rounded text-[10px] font-bold transition-all ${itemsPerPage === size ? 'bg-emerald-500/20 text-emerald-400 border border-emerald-500/30' : 'text-gray-600 hover:text-gray-400'}`}
                            >
                                {size}
                            </button>
                        ))}
                    </div>
                </div>

                {totalPages > 1 && (
                    <div className="flex items-center bg-gray-950 border border-gray-800 rounded-lg p-1 gap-1">
                        <Button
                            variant="ghost"
                            size="sm"
                            className="h-8 w-8 p-0 hover:bg-gray-800 text-gray-400"
                            onClick={() => setCurrentPage(prev => Math.max(1, prev - 1))}
                            disabled={currentPage === 1}
                        >
                            <ChevronDown className="w-4 h-4 rotate-90" />
                        </Button>

                        <div className="flex items-center px-4 gap-2 border-x border-gray-800 px-6">
                            <span className="text-xs font-bold text-emerald-500">{currentPage}</span>
                            <span className="text-xs text-gray-600">/</span>
                            <span className="text-xs text-gray-400 font-medium">{totalPages}</span>
                        </div>

                        <Button
                            variant="ghost"
                            size="sm"
                            className="h-8 w-8 p-0 hover:bg-gray-800 text-gray-400"
                            onClick={() => setCurrentPage(prev => Math.min(totalPages, prev + 1))}
                            disabled={currentPage === totalPages}
                        >
                            <ChevronDown className="w-4 h-4 -rotate-90" />
                        </Button>
                    </div>
                )}
            </div>

            <TreasuryManualEntry
                isOpen={isManualEntryOpen}
                onClose={() => setIsManualEntryOpen(false)}
                orgId={orgId}
                tipo={typeFilter === 'cobro' ? 'cobro' : 'pago'}
                onSuccess={() => { fetchMovements(); setIsManualEntryOpen(false); }}
            />
        </Card >
    )
}

'use client'

import { useState, useEffect } from 'react'
import {
    Dialog,
    DialogContent,
    DialogHeader,
    DialogTitle,
    DialogFooter
} from '@/components/ui/dialog'
import {
    Select,
    SelectContent,
    SelectItem,
    SelectTrigger,
    SelectValue,
} from "@/components/ui/select"
import { Button } from '@/components/ui/button'
import { Input } from '@/components/ui/input'
import { Label } from '@/components/ui/label'
import { Badge } from '@/components/ui/badge'
import { ScrollArea } from '@/components/ui/scroll-area'
import {
    CheckCircle2,
    Plus,
    Trash2,
    Calendar,
    Hash,
    Loader2,
    Search,
    ChevronRight,
    ChevronLeft,
    Wallet,
    Landmark,
    FileText,
    AlertCircle
} from 'lucide-react'
import { createClient } from '@/lib/supabase/client'
import { toast } from 'sonner'

interface TreasuryManualEntryProps {
    isOpen: boolean
    onClose: () => void
    orgId: string
    tipo: 'cobro' | 'pago'
    onSuccess: () => void
}

interface Instrument {
    id: string
    metodo: 'efectivo' | 'transferencia' | 'cheque_terceros' | 'cheque_propio'
    monto: number
    banco: string
    cuenta_id?: string
    detalle_referencia: string
    fecha_disponibilidad: string
}

export function TreasuryManualEntry({ isOpen, onClose, orgId, tipo, onSuccess }: TreasuryManualEntryProps) {
    const [step, setStep] = useState(1)
    const [loading, setLoading] = useState(false)
    const [entidades, setEntidades] = useState<any[]>([])
    const [searchingEntidad, setSearchingEntidad] = useState(false)
    const [searchQuery, setSearchQuery] = useState('')
    const [selectedEntidad, setSelectedEntidad] = useState<any>(null)
    const [cuentasBancarias, setCuentasBancarias] = useState<any[]>([])

    const [pendingInvoices, setPendingInvoices] = useState<any[]>([])
    const [selectedInvoices, setSelectedInvoices] = useState<Record<string, number>>({}) // id -> monto a aplicar
    const [customConcept, setCustomConcept] = useState('')

    const [instruments, setInstruments] = useState<Instrument[]>([
        {
            id: '1',
            metodo: 'efectivo',
            monto: 0,
            banco: '',
            detalle_referencia: '',
            fecha_disponibilidad: new Date().toISOString().split('T')[0]
        }
    ])

    // Reset when opening
    useEffect(() => {
        if (isOpen) {
            setStep(1)
            setSelectedEntidad(null)
            setSearchQuery('')
            setEntidades([]) // Clear previous results
            setSelectedInvoices({})
            setCustomConcept('')
            setInstruments([{
                id: '1',
                metodo: 'efectivo',
                monto: 0,
                banco: '',
                detalle_referencia: '',
                fecha_disponibilidad: new Date().toISOString().split('T')[0]
            }])
            fetchInitialEntities()
            fetchCuentasBancarias()
        }
    }, [isOpen])

    async function fetchCuentasBancarias() {
        const supabase = createClient()
        const { data } = await supabase
            .from('cuentas_bancarias')
            .select('id, nombre, banco, nro_cuenta')
            .eq('organization_id', orgId)
            .order('nombre', { ascending: true })

        if (data) setCuentasBancarias(data)
    }

    async function fetchInitialEntities() {
        const supabase = createClient()
        const targetCat = tipo === 'cobro' ? 'cliente' : 'proveedor'
        setSearchingEntidad(true)
        const { data } = await supabase
            .from('entidades')
            .select('*')
            .eq('organization_id', orgId)
            .in('categoria', [targetCat, 'ambos'])
            .order('razon_social', { ascending: true })
            .limit(10)

        if (data) setEntidades(data)
        setSearchingEntidad(false)
    }

    // Load invoices when entidad is selected
    useEffect(() => {
        if (selectedEntidad) {
            fetchInvoices()
        }
    }, [selectedEntidad])

    async function fetchInvoices() {
        const supabase = createClient()
        const targetTypes = tipo === 'cobro'
            ? ['factura_venta', 'nota_debito_venta', 'nota_credito_venta']
            : ['factura_compra', 'nota_debito_compra', 'nota_credito_compra']

        // Handle variations in legacy data if needed, but primarily use these
        const { data } = await supabase
            .from('comprobantes')
            .select('*')
            .eq('organization_id', orgId)
            .eq('entidad_id', selectedEntidad.id)
            .neq('estado', 'pagado')
            .order('fecha_vencimiento', { ascending: true })

        if (data) setPendingInvoices(data)
    }

    const totalSelected = Object.values(selectedInvoices).reduce((acc, curr) => acc + curr, 0)
    const totalInstruments = instruments.reduce((acc, curr) => acc + (Number(curr.monto) || 0), 0)
    const difference = totalSelected - totalInstruments

    const handleAddInstrument = () => {
        setInstruments([...instruments, {
            id: Date.now().toString(),
            metodo: 'cheque_terceros',
            monto: difference > 0 ? Number(difference.toFixed(2)) : 0,
            banco: '',
            detalle_referencia: '',
            fecha_disponibilidad: new Date().toISOString().split('T')[0]
        }])
    }

    const removeInstrument = (id: string) => {
        if (instruments.length > 1) {
            setInstruments(instruments.filter(i => i.id !== id))
        }
    }

    const updateInstrument = (id: string, updates: Partial<Instrument>) => {
        setInstruments(instruments.map(i => i.id === id ? { ...i, ...updates } : i))
    }

    const toggleInvoice = (inv: any) => {
        const newSelected = { ...selectedInvoices }
        if (newSelected[inv.id]) {
            delete newSelected[inv.id]
        } else {
            newSelected[inv.id] = inv.monto_pendiente
        }
        setSelectedInvoices(newSelected)
    }

    const handleSave = async () => {
        if (Math.abs(difference) > 0.01) {
            toast.error('El total de medios de pago debe coincidir con el total de facturas.')
            return
        }

        setLoading(true)
        const supabase = createClient()

        try {
            // 1. Create Treasury Movement
            const { data: mov, error: movErr } = await supabase
                .from('movimientos_tesoreria')
                .insert({
                    organization_id: orgId,
                    entidad_id: selectedEntidad.id,
                    tipo: tipo,
                    fecha: new Date().toISOString().split('T')[0],
                    monto_total: totalInstruments,
                    concepto: customConcept || `${tipo === 'cobro' ? 'Recibo' : 'Orden de Pago'} manual - ${selectedEntidad.razon_social}`,
                    observaciones: Object.keys(selectedInvoices).length > 0
                        ? `Aplica a ${Object.keys(selectedInvoices).length} comprobantes`
                        : 'Pago a cuenta'
                })
                .select()
                .single()

            if (movErr) throw movErr

            // 2. Insert Instruments
            const instrumentsToInsert = instruments.map(ins => ({
                organization_id: orgId,
                movimiento_id: mov.id,
                metodo: ins.metodo,
                monto: ins.monto,
                banco: ins.banco || null,
                cuenta_id: ins.cuenta_id || null,
                detalle_referencia: ins.detalle_referencia || null,
                fecha_disponibilidad: ins.fecha_disponibilidad,
                estado: ins.metodo === 'efectivo' ? 'conciliado' : 'pendiente'
            }))

            const { error: insErr } = await supabase
                .from('instrumentos_pago')
                .insert(instrumentsToInsert)

            if (insErr) throw insErr

            // 3. Insert Applications and Update Comprobantes
            for (const [invId, montoApli] of Object.entries(selectedInvoices)) {
                // Application
                await supabase.from('aplicaciones_pago').insert({
                    movimiento_id: mov.id,
                    comprobante_id: invId,
                    monto_aplicado: montoApli
                })

                // Update Comprobante
                const inv = pendingInvoices.find(p => p.id === invId)
                if (inv) {
                    const newPendiente = Math.max(0, inv.monto_pendiente - montoApli)
                    const newEstado = newPendiente <= 0.05 ? 'pagado' : 'parcial'

                    await supabase.from('comprobantes')
                        .update({
                            monto_pendiente: newPendiente,
                            estado: newEstado
                        })
                        .eq('id', invId)
                }
            }

            toast.success(`${tipo === 'cobro' ? 'Recibo' : 'Orden de Pago'} registrado correctamente`)
            onSuccess()
            onClose()
        } catch (err: any) {
            console.error('Error saving treasury entry:', err)
            toast.error(`Error: ${err.message}`)
        } finally {
            setLoading(false)
        }
    }

    return (
        <Dialog open={isOpen} onOpenChange={onClose}>
            <DialogContent className="bg-gray-950 border-gray-800 text-white sm:max-w-[850px] p-0 overflow-hidden">
                <DialogHeader className="p-6 border-b border-gray-800">
                    <DialogTitle className="flex items-center gap-2 text-xl">
                        <Wallet className="w-5 h-5 text-emerald-400" />
                        {tipo === 'cobro' ? 'Nuevo Recibo de Cobro' : 'Nueva Orden de Pago'}
                    </DialogTitle>
                </DialogHeader>

                <div className="p-0 overflow-hidden">
                    <div className="flex bg-gray-900/50 border-b border-gray-800">
                        <div className={`px-6 py-3 text-[10px] font-bold uppercase tracking-widest border-b-2 transition-colors ${step === 1 ? 'border-emerald-500 text-white' : 'border-transparent text-gray-500'}`}>
                            1. Entidad y Deuda
                        </div>
                        <div className={`px-6 py-3 text-[10px] font-bold uppercase tracking-widest border-b-2 transition-colors ${step === 2 ? 'border-emerald-500 text-white' : 'border-transparent text-gray-500'}`}>
                            2. Medios de Pago
                        </div>
                    </div>

                    <ScrollArea className="h-[450px]">
                        <div className="p-6">
                            {step === 1 ? (
                                <div className="space-y-6">
                                    {/* Entidad Selection */}
                                    <div className="space-y-3">
                                        <Label className="text-xs font-bold uppercase text-gray-500">Seleccionar {tipo === 'cobro' ? 'Cliente' : 'Proveedor'}</Label>
                                        {!selectedEntidad ? (
                                            <div className="relative">
                                                <Search className="absolute left-3 top-2.5 w-4 h-4 text-gray-500" />
                                                <Input
                                                    placeholder="Buscar por nombre o CUIT..."
                                                    className="bg-gray-900 border-gray-800 pl-9"
                                                    value={searchQuery}
                                                    onChange={async (e) => {
                                                        const term = e.target.value
                                                        setSearchQuery(term)

                                                        if (term.length < 2) {
                                                            if (term.length === 0) fetchInitialEntities()
                                                            else setEntidades([])
                                                            return
                                                        }

                                                        const supabase = createClient()
                                                        const targetCat = tipo === 'cobro' ? 'cliente' : 'proveedor'
                                                        setSearchingEntidad(true)
                                                        const { data } = await supabase
                                                            .from('entidades')
                                                            .select('*')
                                                            .eq('organization_id', orgId)
                                                            .in('categoria', [targetCat, 'ambos'])
                                                            .or(`razon_social.ilike.%${term}%,cuit.ilike.%${term}%`)
                                                            .limit(10)
                                                        if (data) setEntidades(data)
                                                        setSearchingEntidad(false)
                                                    }}
                                                    onFocus={() => {
                                                        if (searchQuery.length === 0 && entidades.length === 0) {
                                                            fetchInitialEntities()
                                                        }
                                                    }}
                                                />
                                                {entidades.length > 0 && !selectedEntidad && (
                                                    <div className="absolute top-full left-0 right-0 mt-1 bg-gray-950 border border-emerald-500/30 rounded-lg shadow-2xl z-50 overflow-hidden max-h-[250px] overflow-y-auto">
                                                        <div className="p-2.5 bg-gray-950 border-b border-gray-800 text-[9px] uppercase font-bold text-gray-500 flex justify-between items-center sticky top-0 z-10">
                                                            <span>{searchQuery.length >= 2 ? 'Resultados de búsqueda' : 'Seleccione una entidad'}</span>
                                                            <span className="text-emerald-500">{entidades.length} hallados</span>
                                                        </div>
                                                        {entidades.map(s => (
                                                            <div
                                                                key={s.id}
                                                                className="p-3 hover:bg-emerald-500/10 cursor-pointer flex justify-between items-center border-b border-gray-800 last:border-0 transition-colors"
                                                                onClick={() => {
                                                                    setSelectedEntidad(s)
                                                                    setEntidades([])
                                                                    setSearchQuery('')
                                                                }}
                                                            >
                                                                <div className="flex flex-col">
                                                                    <span className="font-bold text-sm text-white">{s.razon_social}</span>
                                                                    <span className="text-[10px] text-gray-500 font-mono">{s.cuit}</span>
                                                                </div>
                                                                <ChevronRight className="w-4 h-4 text-gray-700" />
                                                            </div>
                                                        ))}
                                                    </div>
                                                )}
                                            </div>
                                        ) : (
                                            <div className="flex items-center justify-between p-4 bg-emerald-500/5 border border-emerald-500/20 rounded-xl">
                                                <div className="flex items-center gap-3">
                                                    <div className="w-10 h-10 rounded-full bg-emerald-500/10 flex items-center justify-center">
                                                        <FileText className="w-5 h-5 text-emerald-400" />
                                                    </div>
                                                    <div>
                                                        <p className="font-bold text-white">{selectedEntidad.razon_social}</p>
                                                        <p className="text-xs text-gray-500">CUIT: {selectedEntidad.cuit}</p>
                                                    </div>
                                                </div>
                                                <Button variant="ghost" size="sm" onClick={() => setSelectedEntidad(null)} className="text-[10px] font-bold uppercase text-red-400 hover:text-red-300">
                                                    Cambiar
                                                </Button>
                                            </div>
                                        )}
                                    </div>

                                    {/* Custom Concept */}
                                    {selectedEntidad && (
                                        <div className="space-y-3 animate-in fade-in slide-in-from-top-2 duration-300">
                                            <Label className="text-xs font-bold uppercase text-gray-500">Concepto / Referencia</Label>
                                            <div className="relative">
                                                <Plus className="absolute left-3 top-2.5 w-4 h-4 text-emerald-500/50" />
                                                <Input
                                                    placeholder={`Ej: ${tipo === 'cobro' ? 'Cobro anticipado' : 'Pago de servicios'}...`}
                                                    className="bg-gray-900 border-gray-800 pl-9 text-sm"
                                                    value={customConcept}
                                                    onChange={(e) => setCustomConcept(e.target.value)}
                                                />
                                            </div>
                                        </div>
                                    )}

                                    {/* Invoices List */}
                                    {selectedEntidad && (
                                        <div className="space-y-4 pt-2">
                                            <div className="flex justify-between items-end">
                                                <div className="space-y-1">
                                                    <Label className="text-xs uppercase text-gray-500 font-bold tracking-wider">Facturas Pendientes</Label>
                                                    <p className="text-[11px] text-gray-400 italic">Seleccione los comprobantes a cancelar</p>
                                                </div>
                                                <Badge variant="outline" className="bg-emerald-500/5 text-emerald-400 border-emerald-500/20 px-3 py-1 text-xs font-bold font-mono">
                                                    {pendingInvoices.length} HALLADAS
                                                </Badge>
                                            </div>

                                            {pendingInvoices.length === 0 ? (
                                                <div className="p-8 text-center border-2 border-dashed border-gray-800 rounded-xl">
                                                    <p className="text-gray-500 text-sm">No hay comprobantes pendientes para esta entidad.</p>
                                                </div>
                                            ) : (
                                                <div className="grid gap-2">
                                                    {pendingInvoices.map(inv => (
                                                        <div
                                                            key={inv.id}
                                                            className={`p-3 rounded-lg border flex items-center justify-between cursor-pointer transition-all ${selectedInvoices[inv.id] ? 'bg-emerald-500/10 border-emerald-500/40 shadow-[0_0_15px_rgba(16,185,129,0.05)]' : 'bg-gray-900 border-gray-800 hover:border-gray-700'}`}
                                                            onClick={() => toggleInvoice(inv)}
                                                        >
                                                            <div className="flex items-center gap-3">
                                                                <div className={`w-5 h-5 rounded border flex items-center justify-center transition-colors ${selectedInvoices[inv.id] ? 'bg-emerald-500 border-emerald-500' : 'border-gray-700'}`}>
                                                                    {selectedInvoices[inv.id] && <CheckCircle2 className="w-3.5 h-3.5 text-white" />}
                                                                </div>
                                                                <div>
                                                                    <p className="text-xs font-bold text-white uppercase">{inv.tipo.replace('_', ' ')} {inv.nro_factura}</p>
                                                                    <p className="text-[10px] text-gray-500">Vence: {new Date(inv.fecha_vencimiento).toLocaleDateString('es-AR')}</p>
                                                                </div>
                                                            </div>
                                                            <div className="text-right">
                                                                <p className="text-xs font-bold font-mono text-white">
                                                                    {new Intl.NumberFormat('es-AR', { style: 'currency', currency: 'ARS' }).format(inv.monto_pendiente)}
                                                                </p>
                                                                <p className="text-[10px] text-gray-500 uppercase font-bold">Saldo</p>
                                                            </div>
                                                        </div>
                                                    ))}
                                                </div>
                                            )}
                                        </div>
                                    )}
                                </div>
                            ) : (
                                <div className="space-y-6 animate-in slide-in-from-right-4 duration-300">
                                    <div className="p-5 bg-gray-900/50 border border-gray-800 rounded-xl mb-6 flex justify-between items-center bg-[radial-gradient(circle_at_top_right,_var(--tw-gradient-stops))] from-emerald-500/5 via-transparent to-transparent">
                                        <div className="space-y-1">
                                            <p className="text-xs uppercase font-bold text-gray-500 tracking-wider">Resumen de Imputación</p>
                                            <p className="text-lg font-bold text-white tracking-tight">{selectedEntidad?.razon_social}</p>
                                        </div>
                                        <div className="text-right space-y-1">
                                            <p className="text-xs uppercase font-bold text-gray-400 tracking-wider">Total a Cubrir</p>
                                            <p className="text-3xl font-black text-emerald-400 font-mono tracking-tighter">
                                                {new Intl.NumberFormat('es-AR', { style: 'currency', currency: 'ARS' }).format(totalSelected)}
                                            </p>
                                        </div>
                                    </div>

                                    <div className="space-y-4">
                                        <div className="flex justify-between items-center">
                                            <Label className="text-xs font-bold uppercase text-gray-500 tracking-wider">Detalle de Pagos / Recibidos</Label>
                                            <div className="flex items-center gap-2">
                                                {difference !== 0 && (
                                                    <span className={`text-[10px] font-bold flex items-center gap-1 ${Math.abs(difference) < 0.01 ? 'text-emerald-500' : 'text-orange-400'}`}>
                                                        <AlertCircle className="w-3 h-3" />
                                                        Diferencia: {new Intl.NumberFormat('es-AR', { style: 'currency', currency: 'ARS' }).format(difference)}
                                                    </span>
                                                )}
                                                <Button
                                                    onClick={handleAddInstrument}
                                                    variant="outline"
                                                    size="sm"
                                                    className="h-8 text-[10px] font-bold border-emerald-500/30 text-emerald-400 bg-emerald-500/5 hover:bg-emerald-500/10"
                                                >
                                                    <Plus className="w-3.5 h-3.5 mr-1" /> AGREGAR VALOR
                                                </Button>
                                            </div>
                                        </div>

                                        <div className="space-y-3">
                                            {instruments.map((ins, index) => (
                                                <div key={ins.id} className="p-4 bg-gray-900 border border-gray-800 rounded-xl space-y-4">
                                                    <div className="flex justify-between items-center gap-4">
                                                        <div className="grid grid-cols-[1.6fr_1fr] gap-4 flex-1">
                                                            <div className="space-y-1.5">
                                                                <Label className="text-xs uppercase text-gray-500 font-bold">Medio</Label>
                                                                <div className="flex gap-1 pb-1">
                                                                    {['efectivo', 'transferencia', 'cheque_terceros', 'cheque_propio'].map(m => (
                                                                        <button
                                                                            key={m}
                                                                            type="button"
                                                                            onClick={() => updateInstrument(ins.id, { metodo: m as any })}
                                                                            className={`px-2 py-1 rounded text-[8px] font-bold uppercase whitespace-nowrap border transition-all ${ins.metodo === m ? 'bg-emerald-500 border-emerald-500 text-white' : 'bg-gray-950 border-gray-800 text-gray-500 hover:border-gray-700'}`}
                                                                        >
                                                                            {m.replace('_', ' ')}
                                                                        </button>
                                                                    ))}
                                                                </div>
                                                            </div>
                                                            <div className="space-y-1.5">
                                                                <Label className="text-xs uppercase text-gray-500 font-bold">Monto</Label>
                                                                <div className="relative">
                                                                    <div className="absolute left-3 top-1/2 -translate-y-1/2 text-[10px] text-gray-500 font-bold">$</div>
                                                                    <Input
                                                                        type="number"
                                                                        value={ins.monto || ''}
                                                                        onChange={(e) => updateInstrument(ins.id, { monto: parseFloat(e.target.value) || 0 })}
                                                                        className="bg-gray-950 border-gray-800 h-11 text-sm font-mono pl-6 text-right font-bold text-white focus:ring-emerald-500/50"
                                                                    />
                                                                </div>
                                                            </div>
                                                        </div>
                                                        <Button
                                                            variant="ghost"
                                                            size="icon"
                                                            disabled={instruments.length === 1}
                                                            onClick={() => removeInstrument(ins.id)}
                                                            className="h-8 w-8 text-gray-600 hover:text-red-400"
                                                        >
                                                            <Trash2 className="w-4 h-4" />
                                                        </Button>
                                                    </div>

                                                    {(ins.metodo.includes('cheque') || ins.metodo === 'transferencia') && (
                                                        <div className="grid grid-cols-3 gap-3 pt-2 border-t border-gray-800/50">
                                                            <div className="space-y-1">
                                                                <Label className="text-xs uppercase text-gray-500 font-bold">Banco / Cuenta</Label>
                                                                <div className="relative">
                                                                    <Select
                                                                        value={ins.cuenta_id || "none"}
                                                                        onValueChange={(val) => {
                                                                            const cuenta = cuentasBancarias.find(c => c.id === val);
                                                                            updateInstrument(ins.id, {
                                                                                cuenta_id: val === "none" ? undefined : val,
                                                                                banco: cuenta ? cuenta.nombre : ins.banco
                                                                            });
                                                                        }}
                                                                    >
                                                                        <SelectTrigger className="bg-gray-950 border-gray-800 h-11 text-xs pl-8">
                                                                            <Landmark className="absolute left-2 top-3 w-4 h-4 text-gray-600" />
                                                                            <SelectValue placeholder="Seleccionar cuenta..." />
                                                                        </SelectTrigger>
                                                                        <SelectContent className="bg-gray-950 border-gray-800 text-white">
                                                                            <SelectItem value="none" className="text-xs">No vinculado / Otro</SelectItem>
                                                                            {cuentasBancarias.map(c => (
                                                                                <SelectItem key={c.id} value={c.id} className="text-xs">
                                                                                    {c.nombre} ({c.banco})
                                                                                </SelectItem>
                                                                            ))}
                                                                        </SelectContent>
                                                                    </Select>
                                                                </div>
                                                            </div>
                                                            <div className="space-y-1">
                                                                <Label className="text-xs uppercase text-gray-500 font-bold">Nro / Ref</Label>
                                                                <div className="relative">
                                                                    <Hash className="absolute left-2 top-3.5 w-4 h-4 text-gray-600" />
                                                                    <Input
                                                                        placeholder="00012345"
                                                                        value={ins.detalle_referencia}
                                                                        onChange={(e) => updateInstrument(ins.id, { detalle_referencia: e.target.value })}
                                                                        className="bg-gray-950 border-gray-800 h-11 text-xs pl-8 font-mono"
                                                                    />
                                                                </div>
                                                            </div>
                                                            <div className="space-y-1">
                                                                <Label className="text-xs uppercase text-gray-500 font-bold">Vencimiento</Label>
                                                                <div className="relative">
                                                                    <Calendar className="absolute left-2 top-3.5 w-4 h-4 text-gray-600" />
                                                                    <Input
                                                                        type="date"
                                                                        value={ins.fecha_disponibilidad}
                                                                        onChange={(e) => updateInstrument(ins.id, { fecha_disponibilidad: e.target.value })}
                                                                        className="bg-gray-950 border-gray-800 h-11 text-xs pl-8"
                                                                    />
                                                                </div>
                                                            </div>
                                                        </div>
                                                    )}
                                                </div>
                                            ))}
                                        </div>
                                    </div>
                                </div>
                            )}
                        </div>
                    </ScrollArea>
                </div>

                <DialogFooter className="p-6 bg-gray-900/50 border-t border-gray-800 flex justify-between items-center w-full">
                    <div className="flex-1">
                        {step === 2 && (
                            <div className="flex items-center gap-2">
                                <Badge className={`bg-white/5 border-none font-mono ${Math.abs(difference) < 0.01 ? 'text-emerald-400' : 'text-orange-400'}`}>
                                    MEDIOS: {new Intl.NumberFormat('es-AR', { style: 'currency', currency: 'ARS' }).format(totalInstruments)}
                                </Badge>
                            </div>
                        )}
                    </div>
                    <div className="flex gap-2">
                        {step === 1 ? (
                            <>
                                <Button variant="ghost" onClick={onClose} disabled={loading} className="text-gray-500 hover:text-white">
                                    Cancelar
                                </Button>
                                <Button
                                    disabled={!selectedEntidad || totalSelected <= 0}
                                    onClick={() => setStep(2)}
                                    className="bg-emerald-600 hover:bg-emerald-500 text-white font-bold gap-2"
                                >
                                    Siguiente <ChevronRight className="w-4 h-4" />
                                </Button>
                            </>
                        ) : (
                            <>
                                <Button variant="ghost" onClick={() => setStep(1)} disabled={loading} className="text-gray-500 hover:text-white">
                                    <ChevronLeft className="w-4 h-4 mr-1" /> Volver
                                </Button>
                                <Button
                                    onClick={handleSave}
                                    disabled={loading || Math.abs(difference) > 0.02}
                                    className="bg-emerald-600 hover:bg-emerald-500 text-white font-bold px-8 shadow-lg shadow-emerald-500/20"
                                >
                                    {loading ? <Loader2 className="w-4 h-4 animate-spin" /> : <CheckCircle2 className="w-4 h-4 mr-2" />}
                                    Registrar {tipo === 'cobro' ? 'Recibo' : 'Orden De Pago'}
                                </Button>
                            </>
                        )}
                    </div>
                </DialogFooter>
            </DialogContent>
        </Dialog>
    )
}
